            int q = i + 1;
            int p;
            int r = i;
            while (q < line.length() && q > 0) {
                p = q;
                r = i;
                int ind = line.indexOf(sub, p);
                count = 0;
                if (ind != -1) {
                    for (int j = ind; j < line.length(); j++) {
                        if (line.substring(j, j + 1).equalsIgnoreCase(line.substring(r, r + 1))) {
