			for (int i=0;i<s.length()-len+1;i++)
				for (int j=i+1;j<s.length()-len+1;j++)
					if (s.substring(i,i+len).equals(s.substring(j,j+len))){
						out.println(len);
						return;
					}
		out.println(0);
	}


