		char[] s = in.readLine().toCharArray();
		int n = s.length;
		for (int ans = n - 1; ans >= 1; ans--) {
			for (int i = 0; i < n - ans + 1; i++) {
				for (int j = i + 1; j < n - ans + 1; j++) {
					int count = 0;
					for (int k = 0; k < ans; k++) {
						if (s[i + k] == s[j + k]) count++;
						else break;
					}
					if (count == ans) {
						out.print(ans);
						return;
					}
				}
			}
		}
		out.print(0);
	}

