  private void solve() throws Exception
  {
    String s = nextToken();
    int len = s.length();
    KMP kmp = new KMP();
    int r = 0;
    for (int i = 0; i < len; i++)
    {
      for (int j = i + 1; j <= len; j++)
      {
        String cur = s.substring(i, j);
        int count = kmp.search(s, cur);
        if (count >= 2)
          r = max(r, cur.length());
      }
    }
    out.println(r);
  }

  class KMP
  {
    public int search(String text, String pattern)
    {
      int count = 0;
      int n = text.length(), m = pattern.length(), matchPoint = -1;
      char pat[] = pattern.toCharArray(), t[] = text.toCharArray();
      int p[] = prefixTable(pattern);
      int j = 0;
      for (int i = 0; i < n; i++)
      {
        while (j > 0 && pat[j] != t[i])
          j = p[j - 1];
        if (pat[j] == t[i])
          j++;
        if (j == m)
        {
          matchPoint = i - m + 1;
          j = p[j - 1];
          count++;
        }
      }
      return count;
    }

    private int[] prefixTable(String pat)
    {
      int m = pat.length(), p[] = new int[m];
      char s[] = pat.toCharArray();
      int j = 0;
      for (int i = 1; i < m; i++)
      {
        while (j > 0 && s[j] != s[i])
          j = p[j - 1];
        if (s[j] == s[i])
          j++;
        p[i] = j;
      }
      return p;
    }

  }

