public class CodeForces {

    public void solve() throws IOException {
        String s = nextToken();        
        Set<String> set = new HashSet<String>();
        int counter = 0;
        for (int i = 0, l = s.length(); i < l; i++) {
            for (int j = i + 1; j < l; j++) {
                String subst = s.substring(i, j);
                if (!set.contains(subst)) {
                    set.add(subst);
                    if (counts(s.toCharArray(), subst.toCharArray()) > 1) {
                        counter = Math.max(counter, subst.length());
                    }

                }
            }
        }


        writer.print(counter);

    }

    private int counts(char[] s, char[] r) {
        int l = s.length;
        int rl = r.length;
        int arr[] = new int[26];
        Arrays.fill(arr, rl);
        for (int i = rl - 2; i > -1; i--) {
            int margin = (r[i] - 'a');
            if (arr[margin] == rl) {
                arr[margin] = rl - i - 1;
            }
        }
        //search
        int sp = 0;
        int counter = 0;
        while (sp <= l - rl) {
            int oldsp = sp;
            for (int i = rl - 1; i > -1; i--) {
                if (r[i] != s[sp + i]) {
                    if (i == rl - 1) {
                        sp += arr[s[sp + i] - 'a'];

                    } else {
                        sp++;
                    }
                    break;
                }
            }
            if (oldsp == sp) {
                counter++;
                sp++;
            }
        }
        return counter;
    }


