    static class CFireAgain {
        public void solve(int testNumber, FastReader in, PrintWriter out) {
            int n = in.nextInt(), m = in.nextInt(), k = in.nextInt();
            int[][] d = new int[n][m];
            boolean[][] vis = new boolean[n][m];
            Pair<Integer, Integer>[] a = new Pair[k];
            int[] dx = {1, -1, 0, 0};
            int[] dy = {0, 0, 1, -1};
            Queue<Pair<Integer, Integer>> q = new LinkedList<>();
            for (int i = 0; i < n; ++i) {
                Arrays.fill(d[i], -1);
            }
            for (int i = 0; i < k; ++i) {
                a[i] = new Pair<>(in.nextInt() - 1, in.nextInt() - 1);
                d[a[i].x][a[i].y] = 0;
                vis[a[i].x][a[i].y] = true;
                q.add(a[i]);
            }
            while (!q.isEmpty()) {
                Pair<Integer, Integer> u = q.poll();
                for (int i = 0; i < 4; ++i) {
                    int x = u.x + dx[i], y = u.y + dy[i];
                    if (x >= 0 && x < n && y >= 0 && y < m && !vis[x][y]) {
                        vis[x][y] = true;
                        d[x][y] = d[u.x][u.y] + 1;
                        q.add(new Pair<>(x, y));
                    }
                }
            }
            int max = -1;
            Pair<Integer, Integer> ans = new Pair<>(0, 0);
            for (int i = 0; i < n; ++i) {
                for (int j = 0; j < m; ++j) {
                    if (d[i][j] > max) {
                        max = d[i][j];
                        ans.x = i;
                        ans.y = j;
                    }
                }
            }
            out.println(ans.x + 1 + " " + (ans.y + 1));
        }

    }

    static class Pair<U, V> implements Comparable<Pair<U, V>> {
        public U x;
        public V y;

        public Pair(U x, V y) {
            this.x = x;
            this.y = y;
        }

        public int compareTo(Pair<U, V> o) {
            int value = ((Comparable<U>) x).compareTo(o.x);
            if (value != 0) return value;
            return ((Comparable<V>) y).compareTo(o.y);
        }

        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Pair<?, ?> pair = (Pair<?, ?>) o;
            return x.equals(pair.x) && y.equals(pair.y);
        }

        public int hashCode() {
            return Objects.hash(x, y);
        }

    }

    static class FastReader {
        private InputStream stream;
        private byte[] buf = new byte[1024];
        private int curChar;
        private int numChars;
        private FastReader.SpaceCharFilter filter;

        public FastReader(InputStream stream) {
            this.stream = stream;
        }

        public int read() {
            if (numChars == -1) throw new InputMismatchException();
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new InputMismatchException();
                }
                if (numChars <= 0) return -1;
            }
            return buf[curChar++];
        }

        public int nextInt() {
            int c = read();
            while (isSpaceChar(c)) c = read();
            int sgn = 1;
            if (c == '-') {
                sgn = -1;
                c = read();
            }
            int res = 0;
            do {
                if (c < '0' || c > '9') throw new InputMismatchException();
                res *= 10;
                res += c - '0';
                c = read();
            }
            while (!isSpaceChar(c));
            return res * sgn;
        }

        public boolean isSpaceChar(int c) {
            if (filter != null) return filter.isSpaceChar(c);
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

        public interface SpaceCharFilter {
            public boolean isSpaceChar(int ch);

        }

    }
}

