    public void solve() throws IOException {



        n = readInt();

        m = readInt();



        maze = new char[n + 2][m + 2];



        for (int i = 0; i < n + 2; i++) {

            maze[i][0] = '#';

            maze[i][m + 1] = '#';

        }



        for (int j = 0; j < m + 2; j++) {

            maze[0][j] = '#';

            maze[n + 1][j] = '#';

        }



        for (int i = 1; i <= n; i++) {

            for (int j = 1; j <= m; j++) {

                maze[i][j] = '.';

            }

        }



        int[][] dist = new int[n + 2][m + 2];



        for (int i = 0; i < n + 2; i++) {

            for (int j = 0; j < m + 2; j++) {

                dist[i][j] = Integer.MAX_VALUE;

            }

        }



        ArrayDeque<Integer> xValues = new ArrayDeque<Integer>();

        ArrayDeque<Integer> yValues = new ArrayDeque<Integer>();



        int k = readInt();

        for (int i = 0; i < k; i++) {

            int currX = readInt();

            int currY = readInt();

            xValues.add(currX);

            yValues.add(currY);

            dist[currX][currY] = 0;

        }







        while(!xValues.isEmpty()) {

            int x = xValues.poll();

            int y = yValues.poll();



            for (int i = 0; i < 4; i++) {

                int currX = x + dx[i];

                int currY = y + dy[i];



                if (maze[currX][currY] == '.' && dist[currX][currY] > dist[x][y] + 1) {

                    dist[currX][currY] = dist[x][y] + 1;

                    xValues.add(currX);

                    yValues.add(currY);

                }



            }



        }



        int maxDist = 0;

        int indexX = 0;

        int indexY = 0;



        for (int i = 1; i <= n; i++) {

            for (int j = 1; j <= m; j++) {

                if (dist[i][j] >= maxDist) {

                    maxDist = dist[i][j];

                    indexX = i;

                    indexY = j;

                }

            }

        }



        out.print(indexX + " " + indexY);











    }







