            Point init = new Point(x, y);
            init.count = 1;
            q.add(init);
            iss[x][y] = 1;
        }
        Point p = bfs();
        out.println((p.x+1) + " " + (p.y+1));
    }

    private void finish() { this.out.close(); }

    public static void main(String[] args) { 
        R035C obj = new R035C();
        obj.solve();
        obj.finish();
    }
}

