	@Override

	public int compareTo(Pair o) {

		// TODO Auto-generated method stub

	//	Sort in increasing order

		if(w>o.w){

			return 1;

		}else if(w<o.w){

			return -1;

		}else{

			if(h>o.h)

				return 1;

			else if(h<o.h)

				return -1;

			else

			return 0;

		}





	}



