	static boolean isValid(int x, int y) {

		return x >= 0 && y >= 0 && x < N && y < M;

	}



	static class Pair {

		int x, y;



		Pair(int i, int j) {

			x = i;

			y = j;

		}

	}



	static Pair bfs() {

		Queue<Pair> q = new LinkedList<Pair>();

		int[][] dist = new int[N][M];

		for (int i = 0; i < N; i++)

			for (int j = 0; j < M; j++)

				dist[i][j] = -1;

		for (int i = 0; i < K; i++) {

			dist[b[i].x][b[i].y] = 0;

			q.add(b[i]);

		}



		while (!q.isEmpty()) {

			Pair cur = q.remove();

			for (int d = 0; d < 4; d++) {

				int X = cur.x + dx[d];

				int Y = cur.y + dy[d];

				if (isValid(X, Y) && dist[X][Y] == -1) {

					dist[X][Y] = dist[cur.x][cur.y] + 1;

					Pair P = new Pair(X, Y);

					q.add(P);

				}

			}

		}

		int max = -1;

		Pair MX = null;

		for (int i = 0; i < N; i++)

			for (int j = 0; j < M; j++) {

				if (dist[i][j] > max) {

					max = dist[i][j];

					MX = new Pair(i + 1, j + 1);

				}

			}



		return MX;

	}



