	public static void solve() throws Exception {

		Scanner in = new Scanner(new File("input.txt"));

		PrintWriter out = new PrintWriter(new File("output.txt"));



		int n = in.nextInt();

		int m = in.nextInt();



		int[][] time = new int[n][m];

		for(int i = 0; i < n; ++i) {

			Arrays.fill(time[i], Integer.MAX_VALUE);

		}



		int qq = in.nextInt();

		int[] xs = new int[qq];

		int[] ys = new int[qq];



		for(int i = 0; i < qq; ++i){

			xs[i] = in.nextInt() - 1;

			ys[i] = in.nextInt() - 1;

		}





		for(int i = 0; i < n; ++i) {

			for(int j = 0; j < m; ++j) {

				for(int k = 0; k < qq; ++k) {

					int dist = Math.abs(i - xs[k]) + Math.abs(j - ys[k]);

					time[i][j] = Math.min(time[i][j], dist);

				}

			}

		}



		int max = -1;

		int x = -1;

		int y = -1;



		for(int i = 0; i < n; ++i) {

			for(int j = 0; j < m; ++j) if(max < time[i][j]) {



				max = time[i][j];

				x = i + 1;

				y = j + 1;

			} 

		}



		out.println(x + " " + y);



		out.flush();

		out.close();

	}



