		String s = r.readLine();

		String[] sp = s.split(" ");

		n = new Integer(sp[0]);

		m = new Integer(sp[1]);

		boolean[][] v = new boolean[n][m];

		r.readLine();

		s = r.readLine();

		sp = s.split(" ");

		Queue<Integer> q = new LinkedList<Integer>();

