			v[new Integer(sp[i]) - 1][new Integer(sp[i + 1]) - 1] = true;

			q.add(new Integer(sp[i]) - 1);

			q.add(new Integer(sp[i + 1]) - 1);

		}



		int[] dx = { 1, -1, 0, 0 };

