    public static Pair bfs(int x,int y,int xmax,int ymax){
        fired[x][y]=true;
        while(!q.isEmpty()){
            index=(Pair) q.poll();
            int i=(int) index.getKey();
            int j=(int) index.getValue();
            if(i-1>=0){
                if(!fired[i-1][j]){
                fired[i-1][j]=true;
                q.add(new Pair((i-1),j));
                }
            }if(j-1>=0){
                if(!fired[i][j-1]){
                fired[i][j-1]=true;
                q.add(new Pair(i,(j-1)));
                }
            } if(i+1<xmax){
                if(!fired[i+1][j]){
                fired[i+1][j]=true;
                q.add(new Pair(i+1,j));
                }
            } if(j+1<ymax){
                if(!fired[i][j+1]){
                fired[i][j+1]=true;
                q.add(new Pair(i,j+1));
                }
            }
        }    
         return index;   


    }


}

