class TaskC {

    public void solve(int testNumber, InputReader in, PrintWriter out) {

        int n = in.nextInt();

        int m = in.nextInt();

        int k = in.nextInt();

        Queue<Point> points = new LinkedList<Point>();

        int[][] burnTime = new int[n][m];

        boolean[][] visited = new boolean[n][m];

        for (int i = 0; i < k; i++) {

            int x = in.nextInt() - 1;

            int y = in.nextInt() - 1;

            visited[x][y] = true;

            burnTime[x][y] = 0;

            points.add(new Point(x, y));



        }

        int[] dx = new int[]{-1, 0, 0, 1};

        int[] dy = new int[]{0, -1, 1, 0};

        while (points.size() != 0) {

            Point cur = points.poll();

            int x = cur.x;

            int y = cur.y;

            for (int i = 0; i < dx.length; i++) {

                int nextX = x + dx[i];

                int nextY = y + dy[i];

                if (nextX >= 0 && nextX < n && nextY >= 0 && nextY < m && (burnTime[x][y] + 1 < burnTime[nextX][nextY] || !visited[nextX][nextY])) {

                    points.add(new Point(nextX, nextY));

                    visited[nextX][nextY] = true;

                    burnTime[nextX][nextY] = burnTime[x][y] + 1;

                }

            }

        }

        int x, y;

        x = y = 0;

        for (int i = 0; i < n; i++) {

            for (int j = 0; j < m; j++) {

                if (burnTime[i][j] > burnTime[x][y]) {

                    x = i;

                    y = j;

                }

            }

        }

        out.printf("%d %d", x + 1, y + 1);

    }

}



