    		if(eg[i][i] == false)
    		{
    			addedges++;
    		}
    		else
    		{
    			ct++;
    		}

    		for(int j=0;j<n;j++)
    		{
    			if(j!=i && eg[i][j]==false)
    			{
    				addedges++;
    			}
    			else if(j!=i && eg[i][j] == true)
    			{
    				ct++;
    			}
    			if(j!=i && eg[j][i]==false)
    			{
    				addedges++;
    			}
    			else if(j!=i && eg[j][i] == true)
    			{
    				ct++;
    			}
    		}
    		//m - ct

    		boolean row[] = new boolean[n];
    		boolean col[] = new boolean[n];
    		for(int j=0;j<n;j++)
    		{
    			row[j] = eg[i][j];
