public class R227_2_D {
    static ArrayList<Integer>[] graph;
    static int[] right, left;
    static boolean vis[];

    public static boolean dfs(int node) {
        if (vis[node])
            return false;
        vis[node] = true;
        for (int i = 0; i < graph[node].size(); i++) {
            int tmp = graph[node].get(i);
            if (right[tmp] == -1) {
                left[node] = tmp;
                right[tmp] = node;
                return true;
            }
        }
        for (int i = 0; i < graph[node].size(); i++) {
            int tmp = graph[node].get(i);
            if (dfs(right[tmp])) {
                left[node] = tmp;
                right[tmp] = node;
                return true;
            }
        }
        return false;
    }

    public static int getMaxMatch() {
        Arrays.fill(left, -1);
        Arrays.fill(right, -1);
        boolean done = false;
        while (!done) {
            done = true;
            Arrays.fill(vis, false);
            for (int i = 0; i < graph.length; i++) {
                if (left[i] == -1 && dfs(i)) {
                    done = false;
                }
            }
        }
        int res = 0;
        for (int i = 0; i < left.length; i++) {
            res += (left[i] != -1 ? 1 : 0);
        }
        return res;
    }

    public static void main(String[] args) {
        InputReader in = new InputReader(System.in);
        PrintWriter out = new PrintWriter(System.out);
        int V = in.readInt();
        int E = in.readInt();
        Point[] edges = new Point[E];
        for (int i = 0; i < edges.length; i++) {
            edges[i] = new Point(in.readInt() - 1, in.readInt() - 1);
        }
        int best = Integer.MAX_VALUE;
        for (int k = 0; k < V; k++) {
            int n = V - 1;
            graph = new ArrayList[n];
            left = new int[n];
            vis = new boolean[n];
            right = new int[n];
            for (int i = 0; i < graph.length; i++) {
                graph[i] = new ArrayList<Integer>();
            }
            int center = 0;
            for (int i = 0; i < E; i++) {
                if (edges[i].x == k || edges[i].y == k) {
                    center++;
                    continue;
                }
                int src = edges[i].x > k ? edges[i].x - 1 : edges[i].x;
                int dst = edges[i].y > k ? edges[i].y - 1 : edges[i].y;
                graph[src].add(dst);
            }
            int matching = getMaxMatch();
            int addToCenterEdges = 2 * V - 1 - center;
            int removed = E - center - matching;
            int added = n - matching;
            best = Math.min(best, added + removed + addToCenterEdges);
        }
        System.out.println(best);
    }

