    void solve() {
        int n = in.nextInt(), m = in.nextInt();
        int[] fr = new int[m], to = new int[m];
        for (int i = 0; i < m; i++) {
            fr[i] = in.nextInt() - 1;
            to[i] = in.nextInt() - 1;
        }

        int ans = INF;
        for (int i = 0; i < n; i++) {
            int cnt = 0;
            for (int j = 0; j < n; j++) {
                G[j].clear();
                match[j] = -1;
            }
            for (int j = 0; j < m; j++) {
                if (fr[j] == i || to[j] == i) {
                    cnt++;
                } else {
                    G[fr[j]].add(to[j]);
                }
            }

            int other = m - cnt;

            int max = 0;
            for (int j = 0; j < n; j++) {
                cur++;
                if (augment(j)) max++;
            }

            ans = Math.min(ans, 2 * (n - 1) + 1 - cnt + other - max + (n - 1) - max);
        }
        out.println(ans);
    }

    boolean augment(int u) {
        if (used[u] == cur) return false;
        used[u] = cur;
        for (int v : G[u]) {
            if (match[v] < 0 || augment(match[v])) {
                match[v] = u;
                return true;
            }
        }
        return false;
    }

