		c[i][j] = 1;
	}

	find(-1);
	int kq = Integer.MAX_VALUE;

	for(int k = 0; k < n; ++k) {
		if (x[k] != -1) {y[ x[k] ] = -1; x[k] = -1; cnt--; }
		if (y[k] != -1) {x[ y[k] ] = -1; y[k] = -1; cnt--; }
		find(k);

		int t = n*2 - 1 - a.get(k).size() - degIn[k] + c[k][k];
		for(int i = 0; i < n; ++i)
		 if (i!=k) 
			t = t + a.get(i).size() - c[i][k];		
		t = t - cnt + (n-1) - cnt;
		if (kq > t) kq = t;		
	}
	out.println(kq);

}

