	public static int[][] enumFIF(int n, int mod) {
		int[] f = new int[n + 1];
		int[] invf = new int[n + 1];
		f[0] = 1;
		for (int i = 1; i <= n; i++) {
			f[i] = (int) ((long) f[i - 1] * i % mod);
		}
		long a = f[n];
		long b = mod;
		long p = 1, q = 0;
		while (b > 0) {
			long c = a / b;
			long d;
			d = a;
			a = b;
			b = d % b;
			d = p;
			p = q;
			q = d - c * q;
		}
		invf[n] = (int) (p < 0 ? p + mod : p);
		for (int i = n - 1; i >= 0; i--) {
			invf[i] = (int) ((long) invf[i + 1] * (i + 1) % mod);
		}
		return new int[][] { f, invf };
	}


	public static long[] countSameNeighborsSequence(int[] a, int[][] fif, int mod)
	{
		int all = 0;
		for(int v : a)all += v;

		int len = 0;
		long[] dp = new long[all+1];
		dp[0] = 1;
		for(int v : a){
			long[][] pre = new long[all+1][v+1];
			for(int j = 0;j <= all;j++)pre[j][0] = dp[j];
			for(int j = 0;j < v;j++){
				for(int k = 0;k <= all;k++){
					for(int L = j;L >= 0;L--){
						if(pre[k][L] == 0)continue;
						int ca = 2*(j-L);
						int ab = len+j+1-k-ca-L;
						if(ab < 0)continue;
						if(k-1 >= 0){
							pre[k-1][L] += pre[k][L]*k; // aca
							pre[k-1][L] %= mod;
						}
						if(L+1 <= v){
							pre[k][L+1] += pre[k][L]*(ca+L);
							pre[k][L+1] %= mod;
						}
						pre[k][L] = pre[k][L]*ab%mod;
					}
				}
			}

			Arrays.fill(dp, 0);
			for(int k = 0;k <= all;k++){
				for(int L = 0;L <= v && k+L <= all;L++){
					dp[k+L] += pre[k][L];
				}
			}
			for(int k = 0;k <= all;k++){
				dp[k] %= mod;
			}
//			for(int k = 0;k <= all;k++){
//				dp[k] = dp[k] % mod * fif[1][v] % mod;
//			}
			len += v;
		}
		long fifs = 1;
		for(int v : a)fifs = fifs * fif[1][v] % mod;
		for(int k = 0;k <= all;k++)dp[k] = dp[k] * fifs % mod;

		return dp;
	}

