            fs = Arrays.copyOf(fs, fidx);
            long x = 1;
            for (int j : fs) x = x * fact[j] % mod;
            x = x * solve(fs) % mod;
            out.println(x);
        }

        public boolean isSquare(long x) {
            long d = (long) (Math.sqrt(x));
            while (d * d < x) d++;
            while (d * d > x) d--;
            return d * d == x;
        }

        public int solve(int[] freq) {
            int d = AUtils.sum(freq);
            int b = AUtils.max(freq);
            if (d == 0) return 1;
            if (b + b - 1 > d) return 0;
            int[] dp = new int[1];
            dp[0] = 1;
            for (int j = 0; j < freq.length; j++) {
                if (freq[j] == 0) continue;
                int[] nxt = new int[dp.length + freq[j]];
                for (int pgr = 0; pgr < dp.length; pgr++) {
                    for (int cgr = 1; cgr <= freq[j]; cgr++) {
                        nxt[pgr + cgr] += 1L * dp[pgr] * w1[freq[j]][cgr] % mod * ifact[cgr] % mod;
                        if (nxt[pgr + cgr] >= mod) nxt[pgr + cgr] -= mod;
                    }
                }
                dp = nxt;
            }

            int res = 0;
            for (int i = 0; i < dp.length; i++) {
                long x = 1L * dp[i] * fact[i] % mod;
                if ((d - i) % 2 == 0) res += x;
                else res -= x;
                if (res >= mod) res -= mod;
                if (res < 0) res += mod;
            }
            return res;
        }

    }

    static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024];
        private int curChar;
        private int numChars;

        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        public int[] readIntArray(int tokens) {
            int[] ret = new int[tokens];
            for (int i = 0; i < tokens; i++) {
                ret[i] = nextInt();
            }
            return ret;
        }

        public int read() {
            if (this.numChars == -1) {
                throw new InputMismatchException();
            } else {
                if (this.curChar >= this.numChars) {
                    this.curChar = 0;

                    try {
                        this.numChars = this.stream.read(this.buf);
                    } catch (IOException var2) {
                        throw new InputMismatchException();
                    }

                    if (this.numChars <= 0) {
                        return -1;
                    }
                }

                return this.buf[this.curChar++];
            }
        }

        public int nextInt() {
            int c;
            for (c = this.read(); isSpaceChar(c); c = this.read()) {
                ;
            }

            byte sgn = 1;
            if (c == 45) {
                sgn = -1;
                c = this.read();
            }

            int res = 0;

            while (c >= 48 && c <= 57) {
                res *= 10;
                res += c - 48;
                c = this.read();
                if (isSpaceChar(c)) {
                    return res * sgn;
                }
            }

            throw new InputMismatchException();
        }

        public static boolean isSpaceChar(int c) {
            return c == 32 || c == 10 || c == 13 || c == 9 || c == -1;
        }

    }

