    static class COnTheBench {
        Modular mod = new Modular(1e9 + 7);
        Factorial fact = new Factorial(1000, mod);
        Combination comb = new Combination(fact);
        Debug debug = new Debug(true);

        public int f(int i, int j) {
            int ans = mod.mul(fact.fact(i), comb.combination(i + j - 1 - j, j - 1));
            ans = mod.mul(ans, fact.invFact(j));
            return ans;
        }

        public void solve(int testNumber, FastInput in, FastOutput out) {
            int n = in.readInt();
            DSU dsu = new DSU(n);
            long[] a = new long[n];
            for (int i = 0; i < n; i++) {
                a[i] = in.readInt();
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < i; j++) {
                    if (square(a[j] * a[i])) {
                        dsu.merge(j, i);
                        break;
                    }
                }
            }

            IntegerList list = new IntegerList();
            for (int i = 0; i < n; i++) {
                if (dsu.find(i) == i) {
                    list.add(dsu.size[dsu.find(i)]);
                }
            }

            int[] cnts = list.toArray();
            debug.debug("cnts", cnts);
            int m = cnts.length;
            int[][] dp = new int[m + 1][n + 1];
            dp[0][0] = 1;
            for (int i = 1; i <= m; i++) {
                int way = cnts[i - 1];
                for (int j = 0; j <= n; j++) {
                    dp[i][j] = 0;
                    for (int k = 1; k <= j && k <= way; k++) {
                        int contrib = mod.mul(f(way, k), dp[i - 1][j - k]);
                        dp[i][j] = mod.plus(dp[i][j], contrib);
                    }
                }
            }
            debug.debug("dp", dp);

            int ans = 0;
            for (int i = 0; i <= n; i++) {
                int local = mod.mul(dp[m][i], fact.fact(i));
                if ((n - i) % 2 == 1) {
                    local = mod.valueOf(-local);
                }
                ans = mod.plus(ans, local);
            }

            out.println(ans);
        }

        public boolean square(long x) {
            long l = 1;
            long r = (long) 1e9;
            while (l < r) {
                long m = (l + r) / 2;
                if (m * m < x) {
                    l = m + 1;
                } else {
                    r = m;
                }
            }
            return l * l == x;
        }

    }

    static class IntegerList implements Cloneable {
        private int size;
        private int cap;
        private int[] data;
        private static final int[] EMPTY = new int[0];

        public IntegerList(int cap) {
            this.cap = cap;
            if (cap == 0) {
                data = EMPTY;
            } else {
                data = new int[cap];
            }
        }

        public IntegerList(IntegerList list) {
            this.size = list.size;
            this.cap = list.cap;
            this.data = Arrays.copyOf(list.data, size);
        }

        public IntegerList() {
            this(0);
        }

        public void ensureSpace(int req) {
            if (req > cap) {
                while (cap < req) {
                    cap = Math.max(cap + 10, 2 * cap);
                }
                data = Arrays.copyOf(data, cap);
            }
        }

        public void add(int x) {
            ensureSpace(size + 1);
            data[size++] = x;
        }

        public void addAll(int[] x, int offset, int len) {
            ensureSpace(size + len);
            System.arraycopy(x, offset, data, size, len);
            size += len;
        }

        public void addAll(IntegerList list) {
            addAll(list.data, 0, list.size);
        }

        public int[] toArray() {
            return Arrays.copyOf(data, size);
        }

        public String toString() {
            return Arrays.toString(toArray());
        }

        public boolean equals(Object obj) {
            if (!(obj instanceof IntegerList)) {
                return false;
            }
            IntegerList other = (IntegerList) obj;
            return SequenceUtils.equal(data, 0, size - 1, other.data, 0, other.size - 1);
        }

        public int hashCode() {
            int h = 1;
            for (int i = 0; i < size; i++) {
                h = h * 31 + Integer.hashCode(data[i]);
            }
            return h;
        }

        public IntegerList clone() {
            IntegerList ans = new IntegerList();
            ans.addAll(this);
            return ans;
        }

    }

    static class Combination implements IntCombination {
        final Factorial factorial;
        final Modular modular;

        public Combination(Factorial factorial) {
            this.factorial = factorial;
            this.modular = factorial.getModular();
        }

        public Combination(int limit, Modular modular) {
            this(new Factorial(limit, modular));
        }

        public int combination(int m, int n) {
            if (n > m) {
                return 0;
            }
            return modular.mul(modular.mul(factorial.fact(m), factorial.invFact(n)), factorial.invFact(m - n));
        }

    }

    static class FastInput {
        private final InputStream is;
        private byte[] buf = new byte[1 << 13];
        private int bufLen;
        private int bufOffset;
        private int next;

        public FastInput(InputStream is) {
            this.is = is;
        }

        private int read() {
            while (bufLen == bufOffset) {
                bufOffset = 0;
                try {
                    bufLen = is.read(buf);
                } catch (IOException e) {
                    bufLen = -1;
                }
                if (bufLen == -1) {
                    return -1;
                }
            }
            return buf[bufOffset++];
        }

        public void skipBlank() {
            while (next >= 0 && next <= 32) {
                next = read();
            }
        }

        public int readInt() {
            int sign = 1;

            skipBlank();
            if (next == '+' || next == '-') {
                sign = next == '+' ? 1 : -1;
                next = read();
            }

            int val = 0;
            if (sign == 1) {
                while (next >= '0' && next <= '9') {
                    val = val * 10 + next - '0';
                    next = read();
                }
            } else {
                while (next >= '0' && next <= '9') {
                    val = val * 10 - next + '0';
                    next = read();
                }
            }

            return val;
        }

    }

