/**
 * Built using CHelper plug-in
 * Actual solution is at the top
 */
public class Main {
    public static void main(String[] args) {
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;
        InputReader in = new InputReader(inputStream);
        PrintWriter out = new PrintWriter(outputStream);
        OnTheBench solver = new OnTheBench();
        solver.solve(1, in, out);
        out.close();
    }

    static class OnTheBench {
        long MOD = (long) (1e9) + 7;
        long[][] C = new long[333][333];

        public void solve(int testNumber, InputReader in, PrintWriter out) {
            int N = in.nextInt();
            DisjointSet dsu = new DisjointSet(N);
            long[] arr = new long[N];
            setC();
            for (int i = 0; i < N; i++) {
                arr[i] = in.nextInt();
            }
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    long sqrt = (long) (Math.sqrt(arr[i] * arr[j]));
                    long sqrt2 = (long) (Math.ceil(Math.sqrt(arr[i] * arr[j])));
                    if (sqrt * sqrt == arr[i] * arr[j] || sqrt2 * sqrt2 == arr[i] * arr[j]) {
                        dsu.merge(i, j);
                    }
                }
            }
            ArrayList<Integer> sz = new ArrayList<>();
            sz.add(0);
            HashMap<Integer, Integer> seen = new HashMap<>();
            long mult = 1;
            for (int i = 0; i < N; i++) {
                if (!seen.containsKey(dsu.find(i))) {
                    seen.put(dsu.find(i), sz.size());
                    sz.add(0);
                }
                sz.set(seen.get(dsu.find(i)), sz.get(seen.get(dsu.find(i))) + 1);
            }
            for (int i : sz) {
//            if (arr[0] == 285) {
//                out.println(i);
//            }
                mult *= fact(i);
                mult %= MOD;
            }
            long[][] dp = new long[sz.size()][333];
            int sum = 0;
            dp[0][0] = 1;
            for (int n = 1; n < dp.length; n++) {
                for (int ij = 1; ij <= sz.get(n); ij++) {
                    for (int y = 0; y <= sum; y++) {
                        for (int j = 0; j <= Math.min(y, ij); j++) {
                            int i = ij - j;
                            dp[n][y - j + sz.get(n) - ij] += ((((dp[n - 1][y] * C[sum + 1 - y][i]) % MOD * C[y][j]) % MOD) * C[sz.get(n) - 1][ij - 1]) % MOD;
                            dp[n][y - j + sz.get(n) - ij] %= MOD;
                        }
                    }
                }
                sum += sz.get(n);
            }
            out.println((dp[sz.size() - 1][0] * mult) % MOD);
        }

        void setC() {
            for (int i = 0; i <= 332; i++) {
                C[i][0] = 1;
                for (int j = 1; j <= i; j++) {
                    C[i][j] = C[i - 1][j] + C[i - 1][j - 1];
                    C[i][j] %= MOD;
                }
            }
        }

        long fact(int i) {
            long res = 1;
            while (i > 0) {
                res *= i;
                res %= MOD;
                i--;
            }
            return res;
        }

    }

    static class InputReader {
        public BufferedReader reader;
        public StringTokenizer tokenizer;

        public InputReader(InputStream stream) {
            reader = new BufferedReader(new InputStreamReader(stream), 32768);
            tokenizer = null;
        }

        public String next() {
            while (tokenizer == null || !tokenizer.hasMoreTokens()) {
                try {
                    tokenizer = new StringTokenizer(reader.readLine());
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            }
            return tokenizer.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

    }

    static class DisjointSet {
        int[] rank;
        int[] par;

        public DisjointSet(int N) {
            rank = new int[N];
            par = new int[N];
            for (int i = 0; i < N; i++) {
                rank[i] = 1;
                par[i] = i;
            }
        }

        public int find(int x) {
            if (x == par[x]) {
                return x;
            }
            return (par[x] = find(par[x]));
        }

        public void merge(int x, int y) {
            int parX = find(x);
            int parY = find(y);
            if (parX != parY) {
                if (rank[parX] > rank[parY]) {
                    par[parY] = parX;
                    rank[parX] += rank[parY];
                } else {
                    par[parX] = parY;
                    rank[parY] += rank[parX];
                }
            }
        }

    }
}

import java.io.OutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.Iterator;
import java.io.IOException;
import java.util.Comparator;
import java.io.InputStream;

/**
 * Built using CHelper plug-in
 * Actual solution is at the top
 */
public class Main {
    public static void main(String[] args) {
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;
        InputReader in = new InputReader(inputStream);
        PrintWriter out = new PrintWriter(outputStream);
        TaskC solver = new TaskC();
        solver.solve(1, in, out);
        out.close();
    }

    static class TaskC {
        private static final int MOD = (int) 1e9 + 7;

        public void solve(int testNumber, InputReader in, PrintWriter out) {
            int n = in.nextInt();

            int[] primes = getPrimes(40_000);

            int[][] a = new int[n][];
            for (int i = 0; i < n; ++i) {
                int x = in.nextInt();
                IntList divs = new IntList();
                for (int j : primes) {
                    if (j * j > x) {
                        break;
                    }
                    int cnt = 0;
                    while (x % j == 0) {
                        cnt++;
                        x /= j;
                    }
                    if (cnt % 2 == 1) {
                        divs.add(j);
                    }
                }
                if (x > 1) {
                    divs.add(x);
                }
                a[i] = divs.toArray();
            }
            Comparator<int[]> cmp = ((o1, o2) -> {
                for (int i = 0; i < o1.length && i < o2.length; ++i) {
                    if (o1[i] < o2[i]) {
                        return -1;
                    } else if (o2[i] < o1[i]) {
                        return 1;
                    }
                }
                return Integer.compare(o1.length, o2.length);
            });
            Arrays.sort(a, cmp);
            IntList freqsList = new IntList();
            int cnt = 1;
            for (int i = 1; i < n; ++i) {
                if (cmp.compare(a[i], a[i - 1]) == 0) {
                    cnt++;
                } else {
                    freqsList.add(cnt);
                    cnt = 1;
                }
            }
            freqsList.add(cnt);
            int[][] comb = new int[2 * n + 1][2 * n + 1];
            for (int i = 0; i < comb.length; ++i) {
                comb[i][0] = 1;
                for (int j = 1; j <= i; ++j) {
                    comb[i][j] = (comb[i - 1][j] + comb[i - 1][j - 1]) % MOD;
                }
            }
            int[] dp = new int[n];
            int[] ndp = new int[n];
            dp[0] = 1;
            int total = 0;
            int ans = 1;
            for (int x : freqsList.toArray()) {
                Arrays.fill(ndp, 0);
                for (int bad = 0; bad < n; ++bad) {
                    if (dp[bad] == 0) {
                        continue;
                    }
                    for (int putSeparately = 1; putSeparately <= x; ++putSeparately) {
                        for (int breakEq = 0; breakEq <= putSeparately; ++breakEq) {
                            int nState = bad + x - putSeparately - breakEq;
                            if (nState < 0 || nState >= n) {
                                continue;
                            }
                            int rem = total + 1 - bad;
                            int notBreak = putSeparately - breakEq;
                            if (breakEq > bad || notBreak > rem) {
                                continue;
                            }
                            int add = (int) ((long) comb[bad][breakEq] * comb[rem][notBreak] % MOD *
                                    comb[x - 1][putSeparately - 1] % MOD * dp[bad] % MOD);
                            ndp[nState] += add;
                            ndp[nState] %= MOD;
                        }
                    }
                }
                total += x;
                int[] aux = dp;
                dp = ndp;
                ndp = aux;
                ans = (int) ((long) ans * fact(x) % MOD);
            }
            ans = (int) ((long) ans * dp[0] % MOD);
            out.println(ans);
        }

        private int fact(int n) {
            int res = 1;
            for (int i = 2; i <= n; ++i) {
                res = (int) ((long) res * i % MOD);
            }
            return res;
        }

        private int[] getPrimes(int n) {
            boolean[] isPrime = new boolean[n + 1];
            Arrays.fill(isPrime, 2, isPrime.length, true);
            for (int i = 2; i * i <= n; ++i) {
                if (isPrime[i]) {
                    for (int j = i * i; j <= n; j += i) {
                        isPrime[j] = false;
                    }
                }
            }
            IntList primes = new IntList();
            for (int i = 2; i <= n; ++i) {
                if (isPrime[i]) {
                    primes.add(i);
                }
            }
            return primes.toArray();
        }

    }

    static class InputReader {
        private InputStream stream;
        private byte[] buf = new byte[1024];
        private int curChar;
        private int numChars;

        public InputReader(InputStream stream) {
            this.stream = stream;
        }

        public int read() {
            if (numChars == -1)
                throw new UnknownError();
            if (curChar >= numChars) {
                curChar = 0;
                try {
                    numChars = stream.read(buf);
                } catch (IOException e) {
                    throw new UnknownError();
                }
                if (numChars <= 0)
                    return -1;
            }
            return buf[curChar++];
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

        public String next() {
            int c = read();
            while (isSpaceChar(c))
                c = read();
            StringBuffer res = new StringBuffer();
            do {
                res.appendCodePoint(c);
                c = read();
            } while (!isSpaceChar(c));

            return res.toString();
        }

        private boolean isSpaceChar(int c) {
            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
        }

    }

    static interface IntIterator extends Iterator<Integer> {
    }

    static class IntList implements Iterable<Integer> {
        int[] elem;
        int size;

        public IntList() {
            this(0, 0, 1);
        }

        public IntList(int size) {
            this(size, 0, Math.max(1, size));
        }

        public IntList(int size, int value) {
            this(size, value, Math.max(1, size));
        }

        public IntList(int size, int value, int capacity) {
            elem = new int[capacity];
            Arrays.fill(elem, 0, size, value);
            this.size = size;
        }

        private IntList(int... e) {
            elem = e.clone();
            size = e.length;
        }

        public void add(int e) {
            if (size + 1 > elem.length) {
                increaseCapacity();
            }
            elem[size++] = e;
        }

        private void increaseCapacity() {
            changeCapacity(3 * elem.length / 2 + 1);
        }

        private void changeCapacity(int newCapacity) {
            int[] nElem = new int[newCapacity];
            System.arraycopy(elem, 0, nElem, 0, Math.min(elem.length, newCapacity));
            elem = nElem;
        }

        public IntIterator iterator() {
            return new IntIterator() {
                int pos = 0;


                public Integer next() {
                    return IntList.this.elem[pos++];
                }


                public boolean hasNext() {
                    return pos < IntList.this.size;
                }


                public int nextInt() {
                    return IntList.this.elem[pos++];
                }
            };
        }

        public int[] toArray() {
            return Arrays.copyOf(elem, size);
        }

        public int hashCode() {
            int hashCode = 0;
            for (int i = 0; i < size; ++i) {
                hashCode = 31 * hashCode + elem[i];
            }
            return hashCode;
        }

    }
}

import java.io.OutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.List;
import java.util.StringTokenizer;
import java.io.IOException;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.InputStream;
import java.util.ArrayList;

/**
 * Built using CHelper plug-in
 * Actual solution is at the top
 */
public class Main {
    public static void main(String[] args) {
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;
        FastScanner in = new FastScanner(inputStream);
        PrintWriter out = new PrintWriter(outputStream);
        TaskC solver = new TaskC();
        solver.solve(1, in, out);
        out.close();
    }

    static class TaskC {
        final int MOD = (int) (1e9 + 7);
        long[][] C;
        long[] fact;

        public void solve(int testNumber, FastScanner in, PrintWriter out) {
            int n = in.nextInt();
            precalc(n);
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = in.nextInt();
                a[i] = removeSquares(a[i]);
            }
            int[] g = getGroupSizes(a);
            long ans = solve(g);
            for (int x : g) {
                ans = ans * fact[x] % MOD;
            }
            out.println(ans);
        }

        private long solve(int[] a) {
            // For a description, see http://petr-mitrichev.blogspot.com/2017/07/a-week7.html
            long[] d = new long[1];
            d[0] = 1;
            int totalPositions = 1;
            for (int x : a) {
                long[] nd = new long[d.length + x + 1];
                for (int s = 0; s < d.length; s++) {
                    if (d[s] == 0) {
                        continue;
                    }
                    for (int m = 1; m <= x; m++) {
                        for (int p = 0; p <= s && p <= m; p++) {
                            long cur = d[s];
                            cur = cur * C[s][p] % MOD;
                            cur = cur * C[totalPositions - s][m - p] % MOD;
                            cur = cur * f(x, m) % MOD;
                            int ns = s + x - m - p;
                            if (ns >= 0 && ns < nd.length) {
                                nd[ns] += cur;
                                if (nd[ns] >= MOD) {
                                    nd[ns] -= MOD;
                                }
                            }
                        }
                    }
                }
                if (totalPositions == 1) {
                    totalPositions = x + 1;
                } else {
                    totalPositions += x;
                }
                d = nd;
            }
            return d[0];
        }

        private long f(int n, int k) {
            if (n < k) {
                return 0;
            }
            n -= k;
            return C[n + k - 1][k - 1];
        }

        private void precalc(int n) {
            fact = new long[n + 1];
            fact[0] = 1;
            for (int i = 1; i < fact.length; i++) {
                fact[i] = i * fact[i - 1] % MOD;
            }

            C = new long[1000][1000];
            C[0][0] = 1;
            for (int i = 1; i < C.length; i++) {
                C[i][0] = 1;
                for (int j = 1; j < C.length; j++) {
                    C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
                    if (C[i][j] >= MOD) {
                        C[i][j] -= MOD;
                    }
                }
            }
        }

        private int[] getGroupSizes(int[] a) {
            Arrays.sort(a);
            List<Integer> res = new ArrayList<>();
            for (int i = 0; i < a.length; ) {
                int j = i;
                while (j < a.length && a[i] == a[j]) {
                    ++j;
                }
                res.add(j - i);
                i = j;
            }
            int[] r = new int[res.size()];
            for (int i = 0; i < r.length; i++) {
                r[i] = res.get(i);
            }
            return r;
        }

        private int removeSquares(int n) {
            int res = 1;
            for (int d = 2; d * d <= n; d++) {
                if (n % d == 0) {
                    int cur = 0;
                    while (n % d == 0) {
                        n /= d;
                        ++cur;
                    }
                    if (cur % 2 == 1) {
                        res *= d;
                    }
                }
            }
            if (n > 1) {
                res *= n;
            }
            return res;
        }

    }

    static class FastScanner {
        private BufferedReader in;
        private StringTokenizer st;

        public FastScanner(InputStream stream) {
            in = new BufferedReader(new InputStreamReader(stream));
        }

        public String next() {
            while (st == null || !st.hasMoreTokens()) {
                try {
                    st = new StringTokenizer(in.readLine());
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            }
            return st.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

    }
}

import java.io.OutputStream;
