public class Cf840D {

    public static void main(String[] args) {
        FastScanner in = new FastScanner(System.in);
        PrintWriter out = new PrintWriter(System.out);
        Cf840D cf840D = new Cf840D();
        cf840D.run(in, out);
        out.close();
    }


    void run(FastScanner scanner, PrintWriter out) {
        Cf840D htjTree = new Cf840D();
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        int[] a = new int[n+1];
        Set<Integer> set = new TreeSet<>();
        for (int i=1;i<=n;i++) {
            a[i] = scanner.nextInt();
            set.add(a[i]);
        }
        int id = 1;
        Map<Integer,Integer> map = new HashMap<>();
        int[] vals = new int[set.size()+1];
        for (Integer val : set) {
            map.put(val,id);
            vals[id] = val;
            id++;
        }
        htjTree.root[0] = 0;
        htjTree.htj[0] = new Segment();
        for (int i=1;i<=n;i++) {
            htjTree.root[i] = htjTree.curr;
            htjTree.insert(1,id-1,htjTree.root[i-1], htjTree.root[i],map.get(a[i]));
        }
        for (int i=1;i<=m;i++) {
            int l = scanner.nextInt();
            int r = scanner.nextInt();
            int k = scanner.nextInt();
            int index = htjTree.query(1,id-1,htjTree.root[l - 1], htjTree.root[r], (r - l + 1) / k);
            out.println(index == -1 ? index : vals[index]);
        }

    }

    public static class Segment {
        int num;
        int ln;
        int rn;
    }

    int maxn = (int) 3e5+5;
    Segment[] htj = new Segment[maxn*40];
    int[] root = new int[maxn];
    int curr = 1;

    void insert(int l,int r,int pre,int now,int e) {
        Segment L = htj[pre];
        Segment R = new Segment();
        htj[now] = R;
        curr++;
        R.num = L.num+1;
        if (l== r) {
            return;
        }
        R.ln = L.ln;
        R.rn = L.rn;
        int m = (r+l)>>1;
        if (e<=m) {
            R.ln = curr;
            insert(l,m,L.ln, R.ln, e);
        } else {
            R.rn = curr;
            insert(m+1,r,L.rn, R.rn, e);
        }
    }

    int query(int l,int r,int pre,int now,int k) {
        Segment L = htj[pre];
        Segment R = htj[now];
        if (R.num - L.num <= k) {
            return -1;
        }
        if (l == r) {
            return l;
        }
        int m = (l+r)>>1;
        int x = query(l,m,L.ln, R.ln, k);
        if (x != -1)
            return x;
        return query(m+1,r,L.rn, R.rn,k);
    }

