public class Main {
    public static void main(String[] args) {
        InputReader in = new InputReader(System.in);
        PrintWriter out = new PrintWriter(System.out);
        Solver solver = new Solver();
        solver.solve(in, out);
        out.close();
    }

    static class Solver {
        static final int INF = 1_000_000_000;

        public void solve(InputReader in, PrintWriter out) {
            int n = in.nextInt();
            int q = in.nextInt();
            int[] a = new int[n];
            int root = (int) Math.sqrt(n);
            for (int i = 0; i < n; ++i) {
                a[i] = in.nextInt();
            }

            Query[] queries = new Query[q];
            for (int i = 0; i < q; ++i) {
                int l = in.nextInt();
                int r = in.nextInt();
                int k = in.nextInt();
                int blockIndex = l / root;
                queries[i] = new Query(l - 1, r - 1, k, i, blockIndex);
            }
            Arrays.sort(queries);

            int[] freq = new int[n + 1];
            int[] ans = new int[q];
            int currentL = 0;
            int currentR = -1;
            Random rand = new Random();

            for (Query query : queries) {
                while (currentR < query.r) {
                    ++freq[a[++currentR]];
                }
                while (currentL > query.l) {
                    ++freq[a[--currentL]];
                }
                while (currentR > query.r) {
                    --freq[a[currentR--]];
                }
                while (currentL < query.l) {
                    --freq[a[currentL++]];
                }

                int length = currentR - currentL + 1;
                int best = INF;
                for (int iter = 0; iter < 100; ++iter) {
                    int index = currentL + rand.nextInt(currentR - currentL + 1);
                    if ((long) freq[a[index]] * query.k > length && a[index] < best) {
                        best = a[index];
                    }
                }
                ans[query.queryIndex] = best != INF ? best : -1;
            }

            for (int x : ans) {
                out.println(x);
            }
        }

        static class Query implements Comparable<Query> {
            int l;
            int r;
            int k;
            int queryIndex;
            int blockIndex;

            public Query(int l, int r, int k, int queryIndex, int blockIndex) {
                this.l = l;
                this.r = r;
                this.k = k;
                this.queryIndex = queryIndex;
                this.blockIndex = blockIndex;
            }

            @Override
            public int compareTo(Query rhs) {
                if (blockIndex == rhs.blockIndex) {
                    return (blockIndex % 2 == 0 ? r - rhs.r : rhs.r - r);
                }
                return blockIndex - rhs.blockIndex;
            }
        };

    };

    static class InputReader {
        public BufferedReader reader;
        public StringTokenizer tokenizer;

        public InputReader(InputStream stream) {
            reader = new BufferedReader(new InputStreamReader(stream), 32768);
            tokenizer = null;
        }

        public String next() {
            while (tokenizer == null || !tokenizer.hasMoreTokens()) {
                try {
                    tokenizer = new StringTokenizer(reader.readLine());
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            }
            return tokenizer.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

        public long nextLong() {
            return Long.parseLong(next());
        }

    }
}

