import java.io.InputStreamReader;
import java.util.StringTokenizer;
import java.io.BufferedReader;
import java.io.InputStream;

/**
 * Built using CHelper plug-in
 * Actual solution is at the top
 */
public class Main {
    public static void main(String[] args) {
        InputStream inputStream = System.in;
        OutputStream outputStream = System.out;
        FastScanner in = new FastScanner(inputStream);
        PrintWriter out = new PrintWriter(outputStream);
        TaskD solver = new TaskD();
        solver.solve(1, in, out);
        out.close();
    }

    static class TaskD {
        public void solve(int testNumber, FastScanner in, PrintWriter out) {
            int n = in.nextInt();
            int BLOCKSIZE = (int) Math.sqrt(n);
            int numQueries = in.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = in.nextInt() - 1;
            }
            Query[] queries = new Query[numQueries];
            for (int i = 0; i < numQueries; i++) {
                queries[i] = new Query();
                queries[i].l = in.nextInt() - 1;
                queries[i].r = in.nextInt();
                queries[i].k = in.nextInt();
                queries[i].block = queries[i].l / BLOCKSIZE;
                queries[i].id = i;
            }
            Arrays.sort(queries);

            int l = 0;
            int r = 0;
            int[] am = new int[n];
            int[] ans = new int[numQueries];
            Random random = new Random(0);
            for (Query q : queries) {
                while (l > q.l) {
                    --l;
                    ++am[a[l]];
                }
                while (l < q.l) {
                    --am[a[l]];
                    ++l;
                }
                while (r > q.r) {
                    --r;
                    --am[a[r]];
                }
                while (r < q.r) {
                    ++am[a[r]];
                    ++r;
                }
                ans[q.id] = n;
                int need = (r - l) / q.k;
                for (int it = 0; it < 75; it++) {
                    int x = a[l + random.nextInt(r - l)];
                    if (am[x] > need) {
                        ans[q.id] = Math.min(ans[q.id], x);
                    }
                }
                if (ans[q.id] == n) {
                    ans[q.id] = -1;
                } else {
                    ++ans[q.id];
                }
            }

            for (int x : ans) {
                out.println(x);
            }
        }

        class Query implements Comparable<Query> {
            int l;
            int r;
            int k;
            int block;
            int id;

            public int compareTo(Query o) {
                if (block != o.block) {
                    return block - o.block;
                }
                return r - o.r;
            }

        }

    }

    static class FastScanner {
        private BufferedReader in;
        private StringTokenizer st;

        public FastScanner(InputStream stream) {
            in = new BufferedReader(new InputStreamReader(stream));
        }

        public String next() {
            while (st == null || !st.hasMoreTokens()) {
                try {
                    st = new StringTokenizer(in.readLine());
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            }
            return st.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

    }
}

