		Query qs[] = new Query[q];
		Random rnd = new Random(System.currentTimeMillis());
		int answers[] = new int[q];

		for(int i = 0; i < n; i++)
			data[i] = in.nextInt()-1;
		for(int i = 0; i < q; i++)
			qs[i] = new Query(in.nextInt()-1, in.nextInt()-1, in.nextInt(), i);

		Arrays.sort(qs);
		int cL = 0, cR = 0;
		int cnt[] = new int[n];
		for(int i = 0; i < q; i++)
		{
			int l = qs[i].l;
			int r = qs[i].r;
			int k = qs[i].k;
			while(cL > l)
				cnt[data[--cL]]++;
			while(cR <= r)
				cnt[data[cR++]]++;
			while(cL < l)
				cnt[data[cL++]]--;
			while(cR > r+1)
				cnt[data[--cR]]--;

			int need = (r-l+1)/k;
			int ans = Integer.MAX_VALUE;
			for(int j = 0; j < 70; j++)
			{
				int test = l + rnd.nextInt(r-l+1);
				if(cnt[data[test]] > need)
					ans = Math.min(ans, data[test]);
			}

			if(ans == Integer.MAX_VALUE)
				ans = -2;
			answers[qs[i].i] = ans + 1; 
		}

