	public static class Query implements Comparable<Query>
	{
		int l, r, k, i;

		public Query(int ll, int rr, int kk, int ii)
		{
			l = ll;
			r = rr;
			k = kk;
			i = ii;
		}

		@Override
		public int compareTo(Query o)
		{
			if(l/bucket != o.l/bucket)
				return Integer.compare(l/bucket, o.l/bucket);
			else if(r != o.r)
				return Integer.compare(r, o.r);
			else
				return Integer.compare(l, o.l);
		}

		public String toString()
		{
			return l + " " + r + " " + k;
		}
	}

