		public String readString() {
			int c = read();
			while (isSpaceChar(c)) {
				c = read();
			}
			StringBuilder res = new StringBuilder();
			do {
				res.appendCodePoint(c);
				c = read();
			} while (!isSpaceChar(c));
			return res.toString();
		}

		public String nextLine() {
			int c = read();
			while (isSpaceChar(c))
				c = read();
			StringBuilder res = new StringBuilder();
			do {
				res.appendCodePoint(c);
				c = read();
			} while (!isEndOfLine(c));
			return res.toString();
		}

		public boolean isSpaceChar(int c) {
			return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
		}

		private boolean isEndOfLine(int c) {
			return c == '\n' || c == '\r' || c == -1;
		}
	}

	private static void tr(Object... o) {
		if (!(System.getProperty("ONLINE_JUDGE") != null))
			System.out.println(Arrays.deepToString(o));
	}
}

import java.util.Arrays;
import java.util.Scanner;

public class d840 {
	public static void main(String[] args) {
		Scanner in = new Scanner(System.in);
		int N = in.nextInt(), Q = in.nextInt();
		int a[] = new int[N];
		for(int n=0;n<N;n++) {
			a[n] = in.nextInt();
		}
		WT wt = new WT(a);

		StringBuilder sb = new StringBuilder();
		for(int q=0;q<Q;q++) {
			int l = in.nextInt()-1;
			int r = in.nextInt()-1;
			int k = in.nextInt();
			int amount = (r-l+1)/k;
//			System.out.println("amount is "+amount);
			sb.append(wt.hasMoreThanKOfOne(amount, l, r+1)).append('\n');
		}
		System.out.print(sb);
	}
	static class WT{
		int s = Integer.MAX_VALUE, b = Integer.MIN_VALUE;
		int N;
		int[] arr;
		int[] sPtr;
		WT sWav = null, bWav = null;
		WT(int[] arr){
			this.arr = arr;
			N = arr.length;

			for(int n=0;n<N;n++) {
				s = Math.min(s, arr[n]);
				b = Math.max(b, arr[n]);
			}
			sPtr = new int[N+1];
			for(int n=0;n<N;n++) {
				sPtr[n+1] = sPtr[n];
				if(arr[n] <= s + (b-s) / 2) sPtr[n+1]++;
			}
			if(s == b) return;

			int[] sArr = new int[sPtr[N]];
			int[] bArr = new int[N - sPtr[N]];

			for(int n=0;n<N;n++) {
				if(sPtr[n] != sPtr[n+1]) sArr[sPtr[n]] = arr[n];
				else bArr[n-sPtr[n]] = arr[n];
			}

			sWav = new WT(sArr);
			bWav = new WT(bArr);
		}
		int hasMoreThanKOfOne(int k, int l, int r) {
//			System.out.println(l+" "+r+" "+k);
			if(r - l <= k) return -1;
			if(s == b) return s;
			int ret = sWav.hasMoreThanKOfOne(k, sPtr[l], sPtr[r]);
			if(ret != -1) return ret;
			return bWav.hasMoreThanKOfOne(k, l-sPtr[l], r-sPtr[r]);
		}
		int kthLowestValue(int k, int l, int r) {
			if(s == b) return s;
			if(sPtr[r] - sPtr[l] < k) return bWav.kthLowestValue(k - sPtr[r] + sPtr[l], l-sPtr[l], r-sPtr[r]);
			return sWav.kthLowestValue(k, sPtr[l], sPtr[r]);
		}
	}
}

