public class Main{
     static int root[],lc[],rc[],sz[],tot=1;
     public static void main(String []args) throws IOException{
        BufferedReader sc=new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw=new PrintWriter(System.out);
        String s[]=sc.readLine().trim().split(" ");
        int n=Integer.parseInt(s[0]);
        int q=Integer.parseInt(s[1]);
        root=new int[(int)(7e6)];
        lc=new int[(int)(7e6)];
        rc=new int[(int)(7e6)];
        sz=new int[(int)(7e6)];
        root[0]=0;
        pre(0,1,n);
        StringBuilder sb=new StringBuilder();
        s=sc.readLine().trim().split(" ");
        for(int i=1;i<=n;i++){
            int x=Integer.parseInt(s[i-1]);
            root[i]=tot++;
            //System.out.println(tot);
            update(root[i],root[i-1],1,n,x);
        }

        while(q-->0){
            s=sc.readLine().trim().split(" ");
            int l=Integer.parseInt(s[0]);
            int r=Integer.parseInt(s[1]);
            int k=Integer.parseInt(s[2]);
            int len=(r-l+1+k)/k;
            sb.append(query(root[l-1],root[r],1,n,len)+"\n");
        }
        pw.println(sb.toString());
        pw.flush();
        sc.close();
        pw.close();
     }
     public static void update(int curr,int prev,int l,int r,int x){
         sz[curr]=sz[prev]+1;
         if(l>=r)return;
         int val=tot;
         int mid=(l+r)>>1;
         if(x<=mid){
             lc[curr]=tot++;
             rc[curr]=rc[prev];
             update(lc[curr],lc[prev],l,mid,x);
         }else{ 
             rc[curr]=tot++;
             lc[curr]=lc[prev];
             update(rc[curr],rc[prev],mid+1,r,x);
         }
     }
     public static int query(int ql,int qr,int l,int r,int len){
         if(sz[qr]-sz[ql]<len)return -1;
         if(l==r)return l;
         int mid=(l+r)/2;
         int x=query(lc[ql],lc[qr],l,mid,len);
         if(x!=-1)return x;
         return query(rc[ql],rc[qr],mid+1,r,len);
     }
     public static void pre(int curr,int l,int r){
         if(l==r)return;
         lc[curr]=tot++;
         int val=tot;
         int mid=(l+r)>>1;
         pre(lc[curr],l,mid);
         rc[curr]=tot++;
         pre(rc[curr],mid+1,r);
     }
}

import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        FastScanner in = new FastScanner(System.in);
        PrintWriter out = new PrintWriter(System.out);
        new Main().run(in, out);
        out.close();
    }

    // chairman of the tree
    // in each segment, keep value of max occurrence

    int N, M;
    int[] a;

    void run(FastScanner in, PrintWriter out) {

        N = in.nextInt();
        M = in.nextInt();
        a = new int[N+1];
        leftChild = new int[25*N];
        rightChild = new int[25*N];
        sum = new int[25*N];
        root = new int[N+3];

        TreeSet<Integer> ts = new TreeSet<>();
        for (int i = 0; i < N; i++) {
            a[i] = in.nextInt();
            ts.add(a[i]);
        }

        HashMap<Integer, Integer> id = new HashMap<>();
        HashMap<Integer, Integer> rid = new HashMap<>();
        int numUnique = 0;
        for (int num : ts) {
            id.put(num, numUnique);
            rid.put(numUnique, num);
            numUnique++;
        }
        root[0] = buildTree(0, numUnique);

        for (int i = 0; i < N; i++) {
            root[i+1] = update(0, numUnique, root[i], id.get(a[i]));
        }

        while (M-- > 0) {
            int l = in.nextInt();
            int r = in.nextInt();
            int k = in.nextInt();

            int bound = (r-l+1)/k;
            int x = query(0, numUnique, root[l-1], root[r], bound);
            if (x == -1) out.println(-1);
            else out.println(rid.get(x));
        }
    }

    int[] leftChild, rightChild;
    int[] root;
    // sum of all occurrences of all numbers
    int[] sum;
    int sz = 0;

    int buildTree(int l, int r) {
        int currId = ++sz;
        sum[currId] = 0;
        if (l == r) return currId;

        int m = (l+r)>>1;
        leftChild[currId] = buildTree(l, m);
        rightChild[currId] = buildTree(m+1, r);
        return currId;
    }

    // update occurrence of p
    int update(int l, int r, int prevTree, int p) {
        int currId = ++sz;
        sum[currId] = sum[prevTree]+1;

        if (l == r) {
            return currId;
        }

        int m = (l+r)>>1;
        if (p <= m) {
            leftChild[currId] = update(l, m, leftChild[prevTree], p);
            rightChild[currId] = rightChild[prevTree];
        } else {
            leftChild[currId] = leftChild[prevTree];
            rightChild[currId] = update(m+1, r, rightChild[prevTree], p);
        }
        return currId;
    }

    int query(int l, int r, int leftTree, int rightTree, int val) {
        if (l == r) {
            // do we need this if?
            // if we reach here then this condition is always true
            // maybe unless the array is 1 element
            // return sum[rightTree]-sum[leftTree] > val ? l : -1;
            return l;
        }

        int leftChildCount = sum[leftChild[rightTree]] - sum[leftChild[leftTree]];
        int rightChildCount = sum[rightChild[rightTree]] - sum[rightChild[leftTree]];

        // System.out.println(leftChildCount+ " " + rightChildCount  + " " + val);

        int m = (l+r)>>1;
        if (leftChildCount > val) {
            int k = query(l, m, leftChild[leftTree], leftChild[rightTree], val);
            if (k != -1) return k;
        }

        if (rightChildCount > val) {
            int k = query(m+1, r, rightChild[leftTree], rightChild[rightTree], val);
            if (k != -1) return k;
        }

        return -1;
    }



    static class FastScanner {
        BufferedReader br;
        StringTokenizer st;

        public FastScanner(InputStream in) {
            br = new BufferedReader(new InputStreamReader(in));
            st = null;
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }

        long nextLong() {
            return Long.parseLong(next());
        }
    }
}

import java.io.*;
import java.util.*;

public class B {

	static int n, t[], g[], MOD = (int) 1e9 + 7;
	static int[][][] memo1, memo2[], memo3[];

	static int dp1(int idx, int remCnt, int remSum) {
		if (idx == n)
			return remSum == 0 && remCnt == 0 ? 1 : 0;
		if (remCnt < 0 || remSum < 0)
			return 0;
		if (memo1[idx][remCnt][remSum] != -1)
			return memo1[idx][remCnt][remSum];
		int ans = dp1(idx + 1, remCnt, remSum);
		if (g[idx] == 0) {
			ans += dp1(idx + 1, remCnt - 1, remSum - t[idx]);
			if (ans >= MOD)
				ans -= MOD;
		}
		return memo1[idx][remCnt][remSum] = ans;
	}

	static int dp2(int idx, int remCnt1, int remCnt2, int remSum) {

		if (idx == n)
			return remSum == 0 && remCnt1 == 0 && remCnt2 == 0 ? 1 : 0;
		if (remSum < 0 || remCnt1 < 0 || remCnt2 < 0)
			return 0;
		if (memo2[idx][remCnt1][remCnt2][remSum] != -1)
			return memo2[idx][remCnt1][remCnt2][remSum];
		int ans = dp2(idx + 1, remCnt1, remCnt2, remSum);

		if (g[idx] == 1)
			ans += dp2(idx + 1, remCnt1 - 1, remCnt2, remSum - t[idx]);
		else if (g[idx] == 2)
			ans += dp2(idx + 1, remCnt1, remCnt2 - 1, remSum - t[idx]);
		if(ans>=MOD)
			ans-=MOD;
		return memo2[idx][remCnt1][remCnt2][remSum] = ans;
	}

	private static int dp3(int cnt0, int cnt1, int cnt2, int last) {
		if (cnt0 < 0 || cnt1 < 0 || cnt2 < 0)
			return 0;
		if (cnt0 + cnt1 + cnt2 == 0)
			return 1;
		if (memo3[last][cnt0][cnt1][cnt2] != -1)
			return memo3[last][cnt0][cnt1][cnt2];
		long ans = 0;
		if (last != 0)
			ans += dp3(cnt0 - 1, cnt1, cnt2, 0);
		if (last != 1)
			ans += dp3(cnt0, cnt1 - 1, cnt2, 1);
		if (last != 2)
			ans += dp3(cnt0, cnt1, cnt2 - 1, 2);
		return memo3[last][cnt0][cnt1][cnt2] = (int) (ans % MOD);

	}

	public static void main(String[] args) throws IOException {
		Scanner sc = new Scanner();
		PrintWriter out = new PrintWriter(System.out);
		n = sc.nextInt();
		int[] fac = new int[n + 1];
		t = new int[n];
		g = new int[n];
		int[] cnt = new int[3];
		fac[0] = 1;
		for (int i = 1; i <= n; i++)
			fac[i] = (int) (i * 1L * fac[i - 1] % MOD);
		int T = sc.nextInt();
		for (int i = 0; i < n; i++) {
			t[i] = sc.nextInt();
			g[i] = sc.nextInt() - 1;
			cnt[g[i]]++;

		}
		memo1 = new int[n][cnt[0] + 1][T + 1];
		memo2 = new int[n][cnt[1] + 1][cnt[2] + 1][T + 1];
		memo3 = new int[4][cnt[0] + 1][cnt[1] + 1][cnt[2] + 1];
		for (int i = 0; i < n; i++) {
			for (int j = 0; j <= cnt[0]; j++)
				Arrays.fill(memo1[i][j], -1);
			for (int j = 0; j <= cnt[1]; j++)
				for (int k = 0; k <= cnt[2]; k++)
					Arrays.fill(memo2[i][j][k], -1);

		}
		for (int i = 0; i < 4; i++)
			for (int j = 0; j <= cnt[0]; j++)
				for (int k = 0; k <= cnt[1]; k++)
					Arrays.fill(memo3[i][j][k], -1);
		int ans = 0;
		for (int cnt0 = 0; cnt0 <= cnt[0]; cnt0++)
			for (int sum0 = 0; sum0 <= T; sum0++)
				for (int cnt1 = 0; cnt1 <= cnt[1]; cnt1++)
					for (int cnt2 = 0; cnt2 <= cnt[2]; cnt2++) {
						long ways = dp1(0, cnt0, sum0) * 1L * dp2(0, cnt1, cnt2, T - sum0) % MOD;
						ways = ways * dp3(cnt0, cnt1, cnt2, 3) % MOD;
						ways *= fac[cnt0];
						ways %= MOD;
						ways *= fac[cnt1];
						ways %= MOD;
						ways *= fac[cnt2];
						ways %= MOD;
						ans += ways;
						if (ans >= MOD)
							ans -= MOD;
					}
		out.println(ans);
		out.close();

	}

	static class Scanner {
		BufferedReader br;
		StringTokenizer st;

		Scanner() {
			br = new BufferedReader(new InputStreamReader(System.in));
		}

		Scanner(String fileName) throws FileNotFoundException {
			br = new BufferedReader(new FileReader(fileName));
		}

		String next() throws IOException {
			while (st == null || !st.hasMoreTokens())
				st = new StringTokenizer(br.readLine());
			return st.nextToken();
		}

		String nextLine() throws IOException {
			return br.readLine();
		}

		int nextInt() throws IOException {
			return Integer.parseInt(next());
		}

		long nextLong() throws NumberFormatException, IOException {
			return Long.parseLong(next());
		}

		double nextDouble() throws NumberFormatException, IOException {
			return Double.parseDouble(next());
		}

		boolean ready() throws IOException {
			return br.ready();
		}

	}

}

