		int h = m_++;
		uu[h] = u;
		vv[h] = v;
		uv[h] = u ^ v;
		cost[h] = cos;
		cc[h << 1 ^ 0] = cap;
		aa_[u].add(h << 1 ^ 0);
		aa_[v].add(h << 1 ^ 1);
	}
	boolean dijkstra(int s, int t) {
		Arrays.fill(pi, INF);
		pi[s] = 0;
		TreeSet<Integer> pq = new TreeSet<>((u, v) -> pi[u] != pi[v] ? pi[u] - pi[v] : kk[u] != kk[v] ? kk[u] - kk[v] : u - v);
		pq.add(s);
		Integer first;
		while ((first = pq.pollFirst()) != null) {
			int u = first;
			int k = kk[u] + 1;
			ArrayList<Integer> adj = aa_[u];
			for (int h_ : adj)
				if (cc[h_] > 0) {
					int h = h_ >> 1;
					int p = pi[u] + ((h_ & 1) == 0 ? cost_[h] : -cost_[h]);
					int v = u ^ uv[h];
					if (pi[v] > p || pi[v] == p && kk[v] > k) {
						if (pi[v] != INF)
							pq.remove(v);
						pi[v] = p;
						kk[v] = k;
						pq.add(v);
					}
				}
		}
		return pi[t] != INF;
	}
	int dfs(int u, int t, int c) {
		if (u == t || c == 0)
			return c;
		int k = kk[u] + 1;
		ArrayList<Integer> adj = aa_[u];
		for (int h_ : adj) {
			int h = h_ >> 1;
			int v = u ^ uv[h];
			if (kk[v] != k)
				continue;
			int p = pi[u] + ((h_ & 1) == 0 ? cost_[h] : -cost_[h]), f;
			if (pi[v] == p && (f = dfs(v, t, Math.min(c, cc[h_]))) != 0) {
				cc[h_] -= f; cc[h_ ^ 1] += f;
				return f;
			}
		}
		kk[u] = INF;
		return 0;
	}
	int edmonds_karp(int s, int t) {
		cost_ = Arrays.copyOf(cost, m_);
		while (dijkstra(s, t)) {
