		long [] fact, pow, choose [], dp[];

		public Solver(FastScanner in, PrintWriter out) {
			this.in = in;
			this.out = out;
		}

		public void answer(int aa) throws Exception {
			n = in.nextInt();
			m = in.nextLong();

			fact = new long [n+5];
			choose = new long [n+5][n+5];
			dp = new long [n+2][n+2];
			pow = new long [n+2];

			init();

			dp[0][0] = 1;
			for(int i = 0; i <= n; i++) {
				for(int j = 0; j <= i; j++) {
					for(int k = 1; i+k <= n; k++) {
						dp[i+k+1][j+k] += (dp[i][j]*choose[j+k][k]%m)*pow[k-1];
						dp[i+k+1][j+k] %= m;
					}	
				}
			}


			long ans = 0;
			for(int i = 0; i <= n; i++) {
				ans += dp[n+1][i];
				ans %= m;
			}

			out.println(ans);
		}

		public void init() {
			fact[0] = 1;
			for(int i = 1; i <= n+4; i++) {
				fact[i] = (i*fact[i-1])%m;
			}

			pow[0] = 1;
			for(int i = 1; i <= n+1; i++) {
				pow[i] = (2*pow[i-1])%m;
			}

			for(int i = 0; i <= n+4; i++) {
				for(int j = 0; j <= i; j++) {
					choose[i][j] = choose(i, j);
				}
			}
		}

		private long choose(int a, int b) {
			long res = (fact[a] * inv((fact[b] * fact[a-b])%m))%m;
			return res;
		}

		private long power (long x, long y) {
			long res = 1;
			while(y > 0) {
				if(y%2 == 1) res = (res*x)%m;
				x = (x*x)%m;
				y /= 2;
			}
			return (res%m);
		}

		private long inv (long a) {
			return power(a, m-2);
		}

	}

