		return ((fac[n] * ifac[n - k]) % MOD * ifac[k]) % MOD;
	}

	void solve(int T) {
		int n = ni();
		MOD = nl();

		fac[0] = 1;
		ifac[0] = 1;
		p2[0] = 1;
		for (int i = 1; i <= n; ++i) {
			fac[i] = (fac[i - 1] * i) % MOD;
			p2[i] = (p2[i - 1] * 2) % MOD;
		}
		ifac[n] = power(fac[n], MOD - 2);
		for (int i = n - 1; i > 0; --i) {
			ifac[i] = (ifac[i + 1] * (i + 1)) % MOD;
		}
		dp[0][0] = 1;
		for (int i = 0; i <= n; ++i) {
			for (int j = 0; j <= i; ++j) {
				for (int k = 1; i + k <= n; ++k) {
					dp[i + k + 1][j
							+ k] = (dp[i + k + 1][j + k] + ((dp[i][j] * p2[k - 1]) % MOD * bino(k + j, k)) % MOD) % MOD;
				}
			}
		}
		long ans = 0;
		for (int i = 0; i <= n; ++i) {
			ans = (ans + dp[n + 1][i]) % MOD;
		}

		out.println(ans);
	}

	// a^b
	long power(long a, long b) {
		long x = 1, y = a;
		while (b > 0) {
			if (b % 2 != 0) {
				x = (x * y) % MOD;
			}
			y = (y * y) % MOD;
			b /= 2;
		}
		return x % MOD;
	}

