					dp[i+k+1][j+k] += dp[i][j] * fif[1][k] % mod * p2[k-1];
					dp[i+k+1][j+k] %= mod;
				}
			}
//			tr(dp[i]);
		}

		long ans = 0;
		for(int i = 1;i <= N;i++){
			ans += dp[N+1][i] * fif[0][i];
			ans %= mod;
		}
		out.println(ans);
	}

