	static InputReader reader;

	static long[][] binom;

	static void buildBinom(int N){
		int MAX=N+1;
		binom=new long[MAX+1][];
		for (int i=0;i<MAX+1;i++)
			binom[i]=new long[i+1];
		binom[0][0]=1;
		for (int i=1;i<MAX;i++){
			binom[i][0]=1;
			binom[i][i]=1;
			for (int j=0;j<i;j++) {
				binom[i+1][j+1]=(binom[i][j]+binom[i][j+1])%mod;
			}
			//log(binom[i]);
		}
		log("binom done");
	}
	static long mod;

	static long solve(int n) {
		long[] pow2=new long[n+1];
		pow2[0]=1;
		for (int i=1;i<=n;i++) {
			pow2[i]=pow2[i-1]<<1;
			while (pow2[i]>=mod)
				pow2[i]-=mod;
		}
		buildBinom(n);


		long[][] dp=new long[n+1][n+1];
		dp[1][1]=1;
		for (int i=1;i<=n;i++) {
			dp[i][i]=pow2[i-1];
			//log("base:"+dp[i][i]);
			for (int j=1;j<i-1;j++){
				int me=i-j-1;
				for (int cn=1;cn<=j;cn++) {
					//log("j:"+j+" cn:"+cn+" dp:"+dp[j][cn]);
					//log("perm:"+binom[cn+me][cn]);
					dp[i][cn+me]+=(((dp[j][cn]*binom[cn+me][cn])%mod)*pow2[me-1])%mod;
					dp[i][cn+me]%=mod;
				}
			}
		}
		long ans=0;
		for (int i=0;i<=n;i++) {
			ans+=dp[n][i];
			ans%=mod;
		}
		return ans;
	}

