    private static void solve() throws Exception {
        int n = sc.nextInt(), m = sc.nextInt(), k = sc.nextInt();

        int[][] h = new int[n][m - 1];
        int[][] v = new int[n - 1][m];

        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m - 1; ++j) {
                h[i][j] = sc.nextInt();
            }
        }

        for (int i = 0; i < n - 1; ++i) {
            for (int j = 0; j < m; ++j) {
                v[i][j] = sc.nextInt();
            }
        }

        if (k % 2 == 1) {
            for (int i = 0; i < n; ++i) {
                for (int j = 0; j < m; ++j) {
                    if (j > 0) {
                        pw.print(" ");
                    }
                    pw.print(-1);
                }
                pw.println();
            }
            return;
        }

        k = k / 2;

        long[][] d = new long[n][m];
        for (int ki = 0; ki < k; ++ki) {
            long[][] dk = new long[n][m];
            for (int i = 0; i < n; ++i) {
                for (int j = 0; j < m; ++j) {
                    long val = Integer.MAX_VALUE;

                    if (j < m - 1) {
                        val = Math.min(val, d[i][j + 1] + h[i][j]);
                    }

                    if (i < n - 1) {
                        val = Math.min(val, d[i + 1][j] + v[i][j]);
                    }

                    if (j > 0) {
                        val = Math.min(val, d[i][j - 1] + h[i][j - 1]);
                    }

                    if (i > 0) {
                        val = Math.min(val, d[i - 1][j] + v[i - 1][j]);
                    }

                    dk[i][j] = val;
                }
            }
            d = dk;
        }

        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                if (j > 0) {
                    pw.print(" ");
                }
                pw.print(d[i][j] * 2);
            }
            pw.println();
        }
    }

