	public int[][] readGraph(int n, int m) {
		int[][] to = new int[n][];
		int[] sz = new int[n];
		int[] x = new int[m];
		int[] y = new int[m];
		for (int i = 0; i < m; i++) {
			x[i] = in.nextInt() - 1;
			y[i] = in.nextInt() - 1;
			sz[x[i]]++;
			sz[y[i]]++;
		}
		for (int i = 0; i < to.length; i++) {
			to[i] = new int[sz[i]];
			sz[i] = 0;
		}
		for (int i = 0; i < x.length; i++) {
			to[x[i]][sz[x[i]]++] = y[i];
			to[y[i]][sz[y[i]]++] = x[i];
		}
		return to;
	}

	public class Pol {
		double[] coeff;

		public Pol(double[] coeff) {
			this.coeff = coeff;
		}

		public Pol mult(Pol p) {
			double[] ans = new double[coeff.length + p.coeff.length - 1];
			for (int i = 0; i < ans.length; i++) {
				for (int j = Math.max(0, i - p.coeff.length + 1); j < coeff.length && j <= i; j++) {
					ans[i] += coeff[j] * p.coeff[i - j];
				}
			}
			return new Pol(ans);
		}

		public String toString() {
			String ans = "";
			for (int i = 0; i < coeff.length; i++) {
				ans += coeff[i] + " ";
			}
			return ans;
		}

		public double value(double x) {
			double ans = 0;
			double p = 1;
			for (int i = 0; i < coeff.length; i++) {
				ans += coeff[i] * p;
				p *= x;
			}
			return ans;
		}

		public double integrate(double r) {
			Pol p = new Pol(new double[coeff.length + 1]);
			for (int i = 0; i < coeff.length; i++) {
				p.coeff[i + 1] = coeff[i] / fact[i + 1];
			}
			return p.value(r);
		}

		public double integrate(double l, double r) {
			return integrate(r) - integrate(l);
		}
	}

	int mod = 1000000007;

	public int sum(int a, int b) {
		if (a + b >= mod) {
			return a + b - mod;
		}
		return a + b;
	}

	public int diff(int a, int b) {
		if (a < b) {
			return a + mod - b;
		}
		return a - b;
	}

	public int mult(int a, int b) {
		return (int) ((a * 1L * b) % (1L * mod));
	}

	public int pow(int x, int p) {
		if (p <= 0) {
			return 1;
		}
		int ans = pow(x, p / 2);
		ans = mult(ans, ans);
		if (p % 2 == 1) {
			ans = mult(ans, x);
		}
		return ans;
	}

	public int modInv(int x) {
		return pow(x, mod - 2);
	}

	public int c_n_k(int n, int k) {
		if (n < 0 || k < 0 || n - k < 0) {
			return 0;
		}
		return mult(fact[n], mult(factInv[k], factInv[n - k]));
	}

	public class LinAl01 {

		public class Vector {
			BitSet vec;
			BitSet swtch;

			public Vector(BitSet vec, BitSet swtch) {
				this.vec = vec;
				this.swtch = swtch;
			}

			public String toString() {
				String s = "";
				for (int i = 0; i < basis.length; i++) {
					s += (vec.get(i) ? 1 : 0);
				}
				s += " ";
				for (int i = 0; i < basis.length; i++) {
					s += (swtch.get(i) ? 1 : 0);
				}
				return s;
			}
		}

		int n;
		Vector[] basis;

		public void update(Vector v) {
			for (int i = 0; i < n; i++) {
				if (v.vec.get(i)) {
					if (basis[i] == null) {
						basis[i] = v;
						break;
					}
					v.vec.xor(basis[i].vec);
					v.swtch.xor(basis[i].swtch);
				}
			}
		}

		public void diagonalize() {
			for (int i = 0; i < n; i++) {
				if (basis[i] == null) {
					continue;
				}
				for (int j = 0; j < i; j++) {
					if (basis[j] != null && basis[j].vec.get(i)) {
						basis[j].vec.xor(basis[i].vec);
						basis[j].swtch.xor(basis[i].swtch);
					}
				}
			}
		}

	}

	public class Point implements Comparable<Point> {
