	public int[] intersect(int y, int xdown, int ydown, int xup, int yup) {
		if (yup < y || ydown > y || (ydown == yup)) {
			return null;
		}
		long p = xup * 1L * (y - ydown) + xdown * 1L * (yup - y);
		if (p < 0) {
			int[] ans = { -1, 0 };
			return ans;
		}
		long q = 2 * (yup - ydown);
		int[] ans = { (int) (p / q), (int) ((p + q - 1) / q) };
		return ans;
	}

