            int t = x;
            for (int f = 2; f <= x / 2; f++) {
                if (t == 1) {
                    break;
                }
                if (t % f == 0) {
                    res.add(f);
                    while (t % f == 0) {
                        t = t / f;
                    }
                }
            }

            if (t > 1) {
                res.add(t);
            }
