						if(i != n-1)
							ans[i][j] = Math.min(ans[i][j], pans[i+1][j] + 2*edge(i, j, i+1, j));

						if(j != 0)
							ans[i][j] = Math.min(ans[i][j], pans[i][j-1] + 2*edge(i, j, i, j-1));

						if(j != m-1)
							ans[i][j] = Math.min(ans[i][j], pans[i][j+1] + 2*edge(i, j, i, j+1));
					}
				}

				// f.err(k + "\n");
				// errorprint(ans, n, m);

				temp = pans;
				pans = ans;
				ans = temp;
			}

			temp = pans;
			pans = ans;
			ans = temp;
		}

		for(i = 0; i < n; i++)
		{
			for(j = 0; j < m; j++)
			{
				f.out(ans[i][j] + " ");
			}

			f.out("\n");
		}

		f.flush();
	}

