import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.StringTokenizer;

public class Main {
	public static void main(String[] args)throws Exception {
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		StringBuilder sb = new StringBuilder();

		//idea 1 : K/2번까지만 실행해서, 그 최솟값 *2를 하면 된다
		//bfs로 i,j칸에 크거나 같은 값을 가지고 진입하면, 즉시 cut
		StringTokenizer st = new StringTokenizer(br.readLine(), " ");
		n = pint(st.nextToken());
		m = pint(st.nextToken());
		k = pint(st.nextToken());

		//up down left right
		//0 is wall
		map = new int[n][m][4];
		for (int i = 0; i < n; i++) {
			st = new StringTokenizer(br.readLine(), " ");
			for (int j = 0; j < m-1; j++) {
				int temp = pint(st.nextToken());
				map[i][j][3]=temp;
				map[i][j+1][2]=temp;
			}
		}
		for (int i = 0; i < n-1; i++) {
			st = new StringTokenizer(br.readLine(), " ");
			for (int j = 0; j < m; j++) {
				int temp = pint(st.nextToken());
				map[i][j][1]=temp;
				map[i+1][j][0]=temp;
			}
		}

		ans = new int[n][m][k/2+1];
		for (int i = 0; i < n; i++) {
			for (int j = 0; j < m; j++) {
				if(k%2==1) {
					sb.append("-1 ");
					continue;
				}

				int min=rec(i,j,0,k/2);

				sb.append(min*2).append(" ");

			}sb.append("\n");
		}

		System.out.println(sb);

	}
	static int n,m,k;
	//up down left right
	static int[]dx = {-1,1, 0, 0};
	static int[]dy = {0, 0, -1,1};
	static int[][][]map;
	static int[][][]ans;

	static int rec(int x, int y, int cost, int cnt) {
		if(cnt==0) {
			return 0;
		}
		if(ans[x][y][cnt]!=0)return ans[x][y][cnt];

		int temp=Integer.MAX_VALUE;
		for (int i = 0; i < 4; i++) {
			int tx=x+dx[i], ty=y+dy[i];

			if(tx<0||tx>=n||ty<0||ty>=m)continue;

			if(map[x][y][i]!=0) {
				temp=Math.min(temp, rec(tx, ty, cost, cnt-1)+map[x][y][i]);
			}
		}
		ans[x][y][cnt]=temp;

		return ans[x][y][cnt];
	}

	static int pint(String s) {
		return Integer.parseInt(s);
	}
}

