      for(int j=0; j<m-1; ++j) {
        x[i][j] = scan.nextInt();
      }
    }
    for(int i=0; i<n-1; ++i) {
      for(int j=0; j<m; ++j) {
        y[i][j] = scan.nextInt();
      }
    }
    Main mm = new Main(x,y,k);
    mm.go();
  }

}

