        }

        for(i=0;i<N;i++)
        {
            for(int j=0;j<M;j++)
                Arrays.fill(dp[i][j],-1);
        }

        if(K%2==1)
        {
            K/=2;
            answer();
            System.exit(0);
        }

        K/=2;
        for(i=0;i<N;i++)
        {
            for(int j=0;j<M;j++)
                solve(i,j,K);
        }

        answer();
    }
