		private long[] dijkstra(int from) {
			PriorityQueue<Edge> dijk = new PriorityQueue<>(new CompEdge_float());
			long[] d8i = new long[this.dt.size()];
			fill(d8i, INFL);
			dijk.add(new Edge(from, 0L));

			while (!dijk.isEmpty()) {
				Edge dw = dijk.poll();
				if (d8i[dw.v2] > dw.w) {
					d8i[dw.v2] = dw.w;
					for (Edge e : this.get(dw.v2)) {
						long w2 = dw.w + e.w;
						if (d8i[e.v2] > w2)
							dijk.add(new Edge(e.v2, w2));
					}
				}
			}
			return d8i;
		}
	}

