            for(int i=0;i<n;i++){
                for(int j=0;j<m-1;j++){
                    col[i][j] = sc.nextInt();
                }
            }

            for(int i=0;i<n-1;i++){
                for(int j=0;j<m;j++){
                    row[i][j] = sc.nextInt();
                }
            }

            if(k%2!=0){
                for(int i=0;i<n;i++){
                    for(int j=0;j<m;j++){
                        w.print(-1+" ");
                    }
                    w.println("");
                }
            }
            else{
                for(int i=0;i<n;i++){
                    for(int j=0;j<m;j++){
                        long ans = sol(i,j,k/2);
                        w.print((ans*2)+" ");
                    }
                    w.println("");
                }





            }


        }

        w.flush();
        w.close();

    }

    public long sol(int i, int j, int steps){
        if(steps == 0)return 0;
        else if(dp[i][j][steps]!=oo)return dp[i][j][steps];
        else{
            long ans = oo;
            if(i-1>-1){
                ans = Math.min(ans,sol(i-1,j,steps-1)+row[i-1][j]);
            }
            if(i+1<n){
                ans = Math.min(ans,sol(i+1,j,steps-1)+row[i][j]);
            }
            if(j-1>-1){
                ans = Math.min(ans,sol(i,j-1,steps-1)+col[i][j-1]);
            }
            if(j+1<m){
                ans = Math.min(ans,sol(i,j+1,steps-1)+col[i][j]);
            }
            dp[i][j][steps] = Math.min(dp[i][j][steps],ans);
            return dp[i][j][steps];
        }
    }



}

