public class D_CF {

    public static void main(String[] args) {
        FastScanner58 fs = new FastScanner58();
        PrintWriter pw = new PrintWriter(System.out);
        //int t = fs.ni();
        int t = 1;
        // for (int tc = 0; tc < t; tc++) {
        for (int tc = 0; tc < t; tc++) {
            int n = fs.ni();
            int m = fs.ni();
            int k = fs.ni();
            int[][] a = new int[n][m - 1];
            int[][] b = new int[n - 1][m];
            for (int i = 0; i < n; i++) {
                a[i] = fs.intArray(m - 1);
            }
            for (int i = 0; i < n - 1; i++) {
                b[i] = fs.intArray(m);
            }
            int[][] res = new int[n][m];
            Integer[][][] dp = new Integer[n][m][k / 2 + 1];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    res[i][j] = recur(i, j, k / 2, dp, a, b) * 2;
                }
            }
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < res.length; i++) {
                for (int j = 0; j < m; j++) {
                    //matrix[i][j]++;
                    if (k%2==1) {
                        sb.append(-1 + " ");
                    } else {
                        sb.append(res[i][j] + " ");
                    }
                }
                sb.append("\n");
            }
            pw.println(sb);
        }
        pw.close();
    }

    public static int recur(int i, int j, int k, Integer[][][] dp, int[][] a, int[][] b) {
        if (k == 0) {
            return 0;
        }
        int n = (int) (1e9);
        if (dp[i][j][k] != null) {
            return dp[i][j][k];
        }
        if (i != 0) {
            n = Math.min(n, recur(i - 1, j, k - 1, dp, a, b) + b[i - 1][j]);
        }
        if (j != 0) {
            n = Math.min(n, recur(i, j - 1, k - 1, dp, a, b) + a[i][j - 1]);
        }
        if (i != a.length - 1) {
            n = Math.min(n, recur(i + 1, j, k - 1, dp, a, b) + b[i][j]);
        }
        if (j != b[0].length - 1) {
            n = Math.min(n, recur(i, j + 1, k - 1, dp, a, b) + a[i][j]);
        }
        return dp[i][j][k] = n;
    }
}

