    static void solve()
    {

        in = new InputReader(System.in);
        out = new PrintWriter(System.out); 

        int t = 1;

        while(t-- > 0) {
        	int n = in.nextInt();
        	int m = in.nextInt();
        	int K = in.nextInt();

        	long[][] x = new long[n][];

        	for(int i = 0; i < n; i++) {
        		x[i] = in.nextLongArray(m - 1);
        	}

        	long[][] y = new long[n - 1][];
        	for(int i = 0; i < n - 1; i++) {
        		y[i] = in.nextLongArray(m);
        	}

        	if(K % 2 != 0) {
            	for(int i = 0; i < n; i++) {
            		for(int j = 0; j < m; j++) {
            			out.print("-1 ");
            		}
            		out.println();
            	}
        		continue;
        	}
        	K /= 2;

        	long[][][] dp = new long[K + 1][n][m];

        	for(int i = 0; i < n; i++) {
        		for(int j = 0; j < m; j++) {
        			for(int k = 1; k <= K; k++) {
        				dp[k][i][j] = Integer.MAX_VALUE;
        			}
        		}
        	}

        	for(int k = 1; k <= K; k++) {
	        	for(int i = 0; i < n; i++) {
	        		for(int j = 0; j < m; j++) {
	        			if(i + 1 < n) {
	        				dp[k][i][j] = Math.min(dp[k][i][j], dp[k - 1][i + 1][j] + 2 * y[i][j]);
	        			}
	        			if(i - 1 >= 0) {
	        				dp[k][i][j] = Math.min(dp[k][i][j], dp[k - 1][i - 1][j] + 2 * y[i - 1][j]);
	        			}
	        			if(j + 1 < m) {
	        				dp[k][i][j] = Math.min(dp[k][i][j], dp[k - 1][i][j + 1] + 2 * x[i][j]);
	        			}
	        			if(j - 1 >= 0) {
	        				dp[k][i][j] = Math.min(dp[k][i][j], dp[k - 1][i][j - 1] + 2 * x[i][j - 1]);
	        			}
	        		}
	        	}
        	}

        	for(int i = 0; i < n; i++) {
        		for(int j = 0; j < m; j++) {
        			out.print(dp[K][i][j] + " ");
        		}
        		out.println();
        	}

        }

        out.close();

    }

