public class D {

    private static void run() throws IOException {
        int n = in.nextInt();
        int m = in.nextInt();
        int p = in.nextInt();

        int[] dx = {1, -1, 0, 0};
        int[] dy = {0, 0, 1, -1};
        int[][][] map = new int[n][m][4];

        ArrayList<Edge> edges = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m - 1; j++) {
                int len = in.nextInt();
                edges.add(new Edge(new Point[]{new Point(i, j), new Point(i, j + 1)}, len));
                map[i][j][2] = map[i][j + 1][3] = len;
            }
        }
        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < m; j++) {
                int len = in.nextInt();
                edges.add(new Edge(new Point[]{new Point(i, j), new Point(i + 1, j)}, len));
                map[i][j][0] = map[i + 1][j][1] = len;
            }
        }
        if (p % 2 != 0) {
            int[] ans = new int[m];
            for (int i = 0; i < m; i++) {
                ans[i] = -1;
            }
            for (int i = 0; i < n; i++) {
                print_array(ans);
            }
            return;
        }

        edges.sort(Comparator.comparingInt(o -> o.len));

        int[][][] dp = new int[2][n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                int min = Integer.MAX_VALUE;
                for (int k = 0; k < 4; k++) {
                    if (map[i][j][k] == 0) continue;
                    min = Math.min(min, map[i][j][k]);
                }
                dp[1][i][j] = min * 2;
            }
        }

        for (int k = 2; k <= p / 2; k++) {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    dp[k & 1][i][j] = Integer.MAX_VALUE;
                    for (int d = 0; d < 4; d++) {
                        int nx = i + dx[d];
                        int ny = j + dy[d];
                        if (nx < 0 || nx >= n || ny < 0 || ny >= m) continue;

                        dp[k & 1][i][j] = Math.min(dp[(k - 1) & 1][nx][ny] + map[i][j][d] * 2, dp[k&1][i][j]);
                    }
                }
            }
        }

        for (int i = 0; i < n; i++) {
            print_array(dp[(p / 2) & 1][i]);
        }
    }

