	private static int solve(int i, int j, int kLeft) {
		if (i<0 || i>=n || j<0 || j>=m) {
			return (int)1e9;
		} else if (kLeft==0) {
			return 0;
		}

		if (dp[i][j][kLeft]!=null) {
			return dp[i][j][kLeft];
		}

		int ans = (int)1e9;

		final int[] dx = {-1, 1, 0, 0};
		final int[] dy = {0, 0, -1, 1};

		for(int type=0; type<4; type++) {
			int ni = i+dx[type];
			int nj = j+dy[type];
			if (ni<0 || ni>=n || nj<0 || nj>=m) continue;

			int inhibit = 0;
			if (type==0) {
				inhibit = ver[ni][nj];
			} else if (type==1) {
				inhibit = ver[i][j];
			} else if (type==2) {
				inhibit = hor[ni][nj];
			} else {
				inhibit = hor[i][j];
			}

			ans = Math.min(ans, inhibit+solve(ni, nj, kLeft-1));
		}

		return dp[i][j][kLeft]=ans;
	}

