public class Codeforces {

	static int mod=1000_000_007;
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		FastScanner fs=new FastScanner();
		int n=fs.nextInt(),m=fs.nextInt(),k=fs.nextInt();
		PrintWriter out=new PrintWriter(System.out);
		if(k%2!=0) {
			for(int i=0;i<n;i++) {
				for(int j=0;j<m;j++) {
					if(j!=0) out.print(" ");
					out.print(-1);
				}
				out.println();
			}
			out.close();
			return ;
		}
		k/=2;
		int right[][]=new int[n][m-1];
		int down[][]=new int[n-1][m];
		for(int i=0;i<n;i++) {
			for(int j=0;j<m-1;j++) {
				right[i][j]=fs.nextInt();
			}
		}
		for(int i=0;i<n-1;i++) {
			for(int j=0;j<m;j++) {
				down[i][j]=fs.nextInt();
			}
		}
		long dp[][]=new long[n][m];
		long newdp[][]=new long[n][m];
		for(int x=0;x<k;x++) {
			for(int i=0;i<n;i++) {
				for(int j=0;j<m;j++) {
					long ans=Integer.MAX_VALUE;
					if(j>0) ans=Math.min(ans, dp[i][j-1]+right[i][j-1]);
					if(i>0) ans=Math.min(ans, dp[i-1][j]+down[i-1][j]);
					if(j!=m-1) ans=Math.min(ans, dp[i][j+1]+right[i][j]);
					if(i!=n-1) ans=Math.min(ans, dp[i+1][j]+down[i][j]);
					newdp[i][j]=ans;
				}
			}
			dp=newdp;
			newdp=new long[n][m];
		}
		for(int i=0;i<n;i++) {
			for(int j=0;j<m;j++) {
				if(j!=0) out.print(" ");
				out.print(2*dp[i][j]);
			}
			out.println();
		}
		out.close();
	}

	static int gcd(int a,int b) {
		if(b==0) return a;
		return gcd(b,a%b);
	}

	static void sort(int[] a) {

		int n=a.length;
		Random r=new Random();
		for (int i=0; i<a.length; i++) {
			int oi=r.nextInt(n), temp=a[i];
			a[i]=a[oi];
			a[oi]=temp;
		}

		//then sort
		Arrays.sort(a);
	}

