public class Solution1517D {
  public static void main(String[] args) {
    InputReader in = new InputReader(System.in);
    PrintWriter out = new PrintWriter(System.out);
    Solver1517D solver = new Solver1517D();
    solver.solve(0, in, out);
    out.close();
  }

  static class Solver1517D {
    private static final int[][] DIRS = new int[][]{{0, 1}, {0, -1}, {1, 0}, {-1, 0}};
    public void solve(int testNumber, InputReader in, PrintWriter out) {
      int n = in.nextInt(), m = in.nextInt(), k = in.nextInt();
      int[][] wh = new int[n][m];
      int[][] wv = new int[n][m];
      for (int i = 0; i < n; i++) {
        for (int j = 0; j < m - 1; j++) {
          wh[i][j] = in.nextInt();
        }
      }
      for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < m; j++) {
          wv[i][j] = in.nextInt();
        }
      }
      int[][] res = new int[n][m];
      int[][] cache = new int[n*m][k+1];
      for (int i = 0; i < n; i++) {
        Arrays.fill(res[i], -1);
      }
      if (k % 2 == 0) {
        for (int i = 0; i < n; i++) {
          for (int j = 0; j < m; j++) {
            res[i][j] = path(i, j, wh, wv, n, m, k/2, cache) * 2;
          }
        }
      }
      for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
          if (j > 0) {
            out.print(" ");
          }
          out.print(res[i][j]);
        }
        out.println();
      }
    }

    private int path(int i, int j, int[][] wh, int[][] wv, int n, int m, int step, int[][] cache) {
      if (step == 0) {
        return 0;
      }
      int loc = i * m + j;
      if (cache[loc][step] > 0) {
        return cache[loc][step];
      }
      cache[loc][step] = Integer.MAX_VALUE;
      for (int[] dir : DIRS) {
        int newx = i + dir[0];
        int newy = j + dir[1];
        if (newx >= 0 && newx < n && newy >= 0 && newy < m) {
          int l = 0;
          if (dir[0] == 0 && dir[1] == 1) {
            l = wh[i][j];
          } else if (dir[0] == 0 && dir[1] == -1) {
            l = wh[newx][newy];
          } else if (dir[0] == 1 && dir[1] == 0) {
            l = wv[i][j];
          } else {
            l = wv[newx][newy];
          }
          cache[loc][step] = Math.min(cache[loc][step],
              path(newx, newy, wh, wv, n, m, step - 1, cache) + l);
        }
      }
      return cache[loc][step];
    }
  }

