        int c = nextInt();
        cost[i][j][2]=c;
        cost[i+1][j][3]=c;
      }
    }
    int[][][] path = new int[k>=4 ? k/2+1 : 2][n][m];
    for (int i = 0; i<n; i++) {
      for (int j = 0; j<m; j++) {
        int minval = cost[i][j][0];
        minval=min(minval, cost[i][j][1]);
        minval=min(minval, cost[i][j][2]);
        minval=min(minval, cost[i][j][3]);
        path[1][i][j]=minval;
      }
