    		return dp[i][j][left];
    	}

    	int ans=Integer.MAX_VALUE;

    	// left or right
    	ans=Math.min(ans, j>0?r[i][j-1]+solve(i,j-1,left-1):Integer.MAX_VALUE);
    	ans=Math.min(ans, j<m-1?r[i][j]+solve(i,j+1,left-1):Integer.MAX_VALUE);

    	// up or down
    	ans=Math.min(ans, i>0?u[i-1][j]+solve(i-1,j,left-1):Integer.MAX_VALUE);
    	ans=Math.min(ans, i<n-1?u[i][j]+solve(i+1,j,left-1):Integer.MAX_VALUE);

    	return dp[i][j][left]=ans;
    }


