        int k = in.nextInt();
        int[][] col = new int[n][m - 1];
        int[][] row = new int[n - 1][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m - 1; j++) {
                col[i][j] = in.nextInt();
            }
        }
        for (int i = 0; i < n - 1; i++) {
