                for (int j = 0; j < m; j++) {
                    out.print(-1 + " ");
                }
                out.println();
            }
        } else {
            k >>= 1;
            dp = new int[k + 1][n][m];
            for (int[][] a : dp) {
                for (int[] b : a) {
                    Arrays.fill(b, -1);
                }
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
