    static int cal(int x, int y, int step, int[][] row, int[][] col) {
        if (step == 0) {
            return 0;
        }
        if (dp[step][x][y] != -1) {
            return dp[step][x][y];
        }
        int result = Integer.MAX_VALUE;
        if (x < row.length) {
            result = Integer.min(result, cal(x + 1, y, step - 1, row, col) + 2 * row[x][y]);
        }
        if (y < col[x].length) {
            result = Integer.min(result, cal(x, y + 1, step - 1, row, col) + 2 * col[x][y]);
        }
        if (x > 0) {
            result = Integer.min(result, cal(x - 1, y, step - 1, row, col) + 2 * row[x - 1][y]);
        }
        if (y > 0) {
            result = Integer.min(result, cal(x, y - 1, step - 1, row, col) + 2 * col[x][y - 1]);
        }
        return dp[step][x][y] = result;
    }

    public static int[] KMP(String val) {
        int i = 0;
        int j = -1;
        int[] result = new int[val.length() + 1];
        result[0] = -1;
        while (i < val.length()) {
            while (j >= 0 && val.charAt(j) != val.charAt(i)) {
                j = result[j];
            }
            j++;
            i++;
            result[i] = j;
        }
        return result;

    }

    public static boolean nextPer(int[] data) {
        int i = data.length - 1;
        while (i > 0 && data[i] < data[i - 1]) {
            i--;
        }
        if (i == 0) {
            return false;
        }
        int j = data.length - 1;
        while (data[j] < data[i - 1]) {
            j--;
        }
        int temp = data[i - 1];
        data[i - 1] = data[j];
        data[j] = temp;
        Arrays.sort(data, i, data.length);
        return true;
    }

    public static int digit(long n) {
        int result = 0;
        while (n > 0) {
            n /= 10;
            result++;
        }
        return result;
    }

    public static double dist(long a, long b, long x, long y) {
        double val = (b - a) * (b - a) + (x - y) * (x - y);
        val = Math.sqrt(val);
        double other = x * x + a * a;
        other = Math.sqrt(other);
        return val + other;

    }

