	static long rec(int i, int j, int depth){
		if(depth==k/2) return 0;
		if(dp[i][j][depth]!=-1) return dp[i][j][depth];      
		long mn = Long.MAX_VALUE;
		if(i+1<=n) mn = Math.min(mn,rec(i+1,j,depth+1)+w2[i+1][j]);
		if(j+1<=m) mn = Math.min(mn,rec(i,j+1,depth+1)+w1[i][j+1]);
		if(i>1) mn = Math.min(mn,rec(i-1,j,depth+1)+w2[i][j]);
		if(j>1) mn = Math.min(mn,rec(i,j-1,depth+1)+w1[i][j]);
		return dp[i][j][depth] = mn;		
	}

