    void test_case() {
        int n = sc.nextInt();
        int m = sc.nextInt();
        int k = sc.nextInt();
        ArrayDeque<int[]>[][] adj = new ArrayDeque[n][m];
        for(int i = 0; i < n; i++) {
            for(int j = 0; j < m; j++) {
                adj[i][j] = new ArrayDeque<>();
            }
        }

        for(int i = 0; i < n; i++) {
            for(int j = 0; j < m-1; j++) {
                int cost = sc.nextInt();
                int u_i = i;
                int u_j = j;
                int v_i = i;
                int v_j = j+1;
                adj[u_i][u_j].add(new int[] {v_i, v_j, cost});
                adj[v_i][v_j].add(new int[] {u_i, u_j, cost});
            }
        }

        for(int i = 0; i < n-1; i++) {
            for(int j = 0; j < m; j++) {
                int cost = sc.nextInt();
                int u_i = i;
                int u_j = j;
                int v_i = i+1;
                int v_j = j;
                adj[u_i][u_j].add(new int[] {v_i, v_j, cost});
                adj[v_i][v_j].add(new int[] {u_i, u_j, cost});
            }
        }
        if(k % 2 == 1) {
            for(int i = 0; i < n; i++) {
                for(int j = 0; j < m; j++) {
                    print((-1) + " ");
                }
                println();
            }   
            return;
        }
        k /= 2;
        int[][][] dp = new int[n][m][k+1];
        for(int it = 1; it <= k; it++) {
            for(int i = 0; i < n; i++) {
                for(int j = 0; j < m; j++) {
                    int best = 1<<30;
                    for(int[] v : adj[i][j]) {
                        int ii = v[0];
                        int jj = v[1];
                        int cost = v[2];
                        best = Math.min(best, 2 * cost + dp[ii][jj][it-1]);
                    }
                    dp[i][j][it] = best;
                }
            }
        }
        for(int i = 0; i < n; i++) {
            for(int j = 0; j < m; j++) {
                print(dp[i][j][k] + " ");
            }
            println();
        }       
    }

