public class Main {
	static class node
	{
		int a,b,v;
		public node(int a,int b,int v)
		{
			this.a=a;
			this.b=b;
			this.v=v;
		}
	}
	static int inf=0x3f3f3f3f;
	public static void main(String[]args) throws IOException {
		Scanner in=new Scanner(System.in);
		int n=in();
		int m=in();
		int num=in();
		if(num%2==1) {
			for(int i=0;i<n;i++) {
				for(int j=0;j<m;j++) {
					out.print("-1 ");
				}
				out.println();
			}
			out.flush();
			return;
		}
		ArrayList<node>[][]map=new ArrayList[n][m];
		for(int i=0;i<n;i++) {
			map[i][0]=new ArrayList<node>();
			for(int j=1;j<m;j++) {
				map[i][j]=new ArrayList<node>();
				int v=in();
				map[i][j-1].add(new node(i,j,v));
				map[i][j].add(new node(i,j-1,v));
			}
		}
		for(int i=1;i<n;i++) {
			for(int j=0;j<m;j++) {
				int v=in();
				map[i-1][j].add(new node(i,j,v));
				map[i][j].add(new node(i-1,j,v));
			}
		}
		num>>=1;
		int [][][]dp=new int[n][m][num+1];
		for(int k=1;k<=num;k++) {
			for(int i=0;i<n;i++) {
				for(int j=0;j<m;j++) {
					dp[i][j][k]=inf;
					for(node node:map[i][j]) {
						dp[i][j][k]=Math.min(dp[i][j][k],dp[node.a][node.b][k-1]+node.v);
					}
				}
			}
		}
		for(int i=0;i<n;i++)
		{
			for(int j=0;j<m;j++)
			{
				out.print((dp[i][j][num]<<1)+" ");
			}
			out.println();
		}
		out.flush();
	}
