    static int solve(int i, int j, int rem) {
        if (rem == 0) {
            return 0;
        }
        if (i < 0 || j < 0 || i >= n || j >= m) {
            return 0;
        }
        if(dp[i][j][rem]!=-1){
            return dp[i][j][rem];
        }
        dp[i][j][rem]= Math.min(j<m-1?(hor[i][j] + solve(i, j + 1, rem - 1)):Integer.MAX_VALUE,
                Math.min(j > 0 ? (hor[i][j - 1] + solve(i, j - 1, rem - 1)) : Integer.MAX_VALUE,
                        Math.min(i<n-1?(ver[i][j] + solve(i + 1, j, rem - 1)):Integer.MAX_VALUE,
                                i > 0 ? (ver[i - 1][j] + solve(i - 1, j, rem - 1)) : Integer.MAX_VALUE)));
        return dp[i][j][rem];
    }

