	public static void main(String[] args) {
		sc=new FastReader();
		PrintWriter out=new PrintWriter(System.out);
		//DP[I][J][K] -> MINIMUM WEIGHT TO GET TO (I,J) IN K MOVES

		//DP[I][J][K] = MAX(DP[I-DIR][J-DIR][K-1]+ E[DIR])
		int n=sc.nextInt(),m=sc.nextInt(),moves=sc.nextInt();
		int v[][]=new int[n][m-1],h[][]=new int[n-1][m];
		//V[I][J] -> THE EDGE BETWEEN VERTEX-[I][J] AND VERTEX- [I][J+1]  
		//H[I][J] -> THE EDGE BETWEEN VERTEX-[I][J] AND VERTEX- [I+1][J]  

		for(int i=0;i<n;i++)v[i]=sc.readArray(m-1);
		for(int i=0;i+1<n;i++)h[i]=sc.readArray(m);

		long dp[][][]=new long[n][m][moves/2+1];
		if(moves%2==1) {
			for(int i=0;i<n;i++) {
				for(int j=0;j<m;j++)Arrays.fill(dp[i][j], -1);
			}
		}
		else {
			for(int i=0;i<n;i++) {
