						//LEFT
						if(j>0)dp[i][j][k]=Math.min(dp[i][j-1][k-1]+2*v[i][j-1],dp[i][j][k]);
						//DOWN
						if(i+1<n)dp[i][j][k]=Math.min(dp[i+1][j][k-1]+2*h[i][j], dp[i][j][k]);
						//RIGHT
						if(j+1<m)dp[i][j][k]=Math.min(dp[i][j+1][k-1]+2*v[i][j],dp[i][j][k]);
					}
				}
			}
		}
		for(int i=0;i<n;i++) {
			for(int j=0;j<m;j++)out.print(dp[i][j][moves/2]+" ");
