		m = Integer.parseInt(st.nextToken());
		k = Integer.parseInt(st.nextToken());
		if (k % 2 == 1) {
			for (int i = 0; i < n; i++) {
				for (int j = 0; j < m; j++) {
					out.print(-1 + " ");
				}
				out.println();
			}
			return;
		}
		dp = new long[n][m][k/2+1];
		for (long[][] a: dp) for (long[] b: a) Arrays.fill(b, Long.MAX_VALUE/5);
		adj = new List[n][m];
		for (int i = 0; i < n; i++) {
			for (int j = 0; j < m; j++) adj[i][j] = new ArrayList<Edge>();
		}
		for (int i = 0; i < n; i++) {
			st = new StringTokenizer(br.readLine());
			for (int j = 0; j < m-1; j++) {
				long x = Integer.parseInt(st.nextToken());
				adj[i][j].add(new Edge(i, j+1, x));
				adj[i][j+1].add(new Edge(i,j,x));
			}
		}
		for (int i = 0; i < n-1; i++) {
			st = new StringTokenizer(br.readLine());
			for (int j = 0; j < m; j++) {
				long x = Integer.parseInt(st.nextToken());
				adj[i+1][j].add(new Edge(i, j, x));
				adj[i][j].add(new Edge(i+1,j,x));
			}
		}
		for (int i = 0; i < n; i++) {
			for (int j = 0; j < m; j++) {
				long ans = solve(i,j,0)*2;
				out.print(ans + " ");
			}
			out.println();
		}
	}
}

