    ArrayList<long[]>[] graph;
    void work() {
        int[][] dir=new int[][]{{0,-1},{-1,0},{0,1},{1,0}};
        int n=ni(),m=ni(),k=ni();
        int[][] H=new int[n][m-1];
        int[][] V=new int[n-1][m];
        for(int i=0;i<n;i++){
            for(int j=0;j<m-1;j++){
                H[i][j]=ni();
            }
        }
        for(int i=0;i<n-1;i++){
            for(int j=0;j<m;j++){
                V[i][j]=ni();
            }
        }
        if(k%2==1){
            for(int i=0;i<n;i++){
                for(int j=0;j<m;j++){
                    out.print(-1+" ");
                }
                out.println();
            }
            return;
        }
        k/=2;
        long[][] dp=new long[n][m];
        for(int p=0;p<k;p++){
            long[][] ndp=new long[n][m];
            for(long[] nd:ndp){
                Arrays.fill(nd,inf);
            }
            for(int i=0;i<n;i++){
                for(int j=0;j<m;j++){
                    for(int d=0;d<4;d++){
                        int ni=dir[d][0]+i,nj=dir[d][1]+j;
                        if(ni>=0&&ni<n&&nj>=0&&nj<m){
                            int w=0;
                            if(d==0){
                                w=H[i][j-1];
                            }else if(d==1){
                                w=V[i-1][j];
                            }else if(d==2){
                                w=H[i][j];
                            }else{
                                w=V[i][j];
                            }
                            ndp[ni][nj]=Math.min(ndp[ni][nj],dp[i][j]+w);
                        }
                    }
                }
            }
            dp=ndp;
        }
        for(int i=0;i<n;i++){
            for(int j=0;j<m;j++){
                out.print((dp[i][j]*2)+" ");
            }
            out.println();
        }
    }

