	static int bore(int i, int j, int k) {
		if(dp[i][j][k]>0)
			return dp[i][j][k];
		if(k==0) return 0;
		dp[i][j][k] = Integer.MAX_VALUE;
		if(i>0)
			dp[i][j][k]=Math.min(bore(i-1, j, k-1) + v[i-1][j], dp[i][j][k]);
		if(i<n-1)
			dp[i][j][k]=Math.min(bore(i+1, j, k-1) + v[i][j], dp[i][j][k]);
		if(j>0)
			dp[i][j][k]=Math.min(bore(i, j-1, k-1) + h[i][j-1], dp[i][j][k]);
		if(j<m-1)
			dp[i][j][k]=Math.min(bore(i, j+1, k-1) + h[i][j], dp[i][j][k]);
		return dp[i][j][k];
	}

	static boolean isPartition(int arr[], int n) {
		int sum = 0;
	    int i, j;

	    // Calculate sum of all elements
	    for (i = 0; i < n; i++)
	        sum += arr[i];

	    if (sum % 2 != 0)
	        return false;

	    boolean part[][]=new boolean[sum/2+1][n+1];

	    // initialize top row as true
	    for (i = 0; i <= n; i++)
	        part[0][i] = true;

	    // initialize leftmost column, except part[0][0], as false
	    for (i = 1; i <= sum / 2; i++)
	        part[i][0] = false;

	    // Fill the partition table in bottom up manner
	    for (i = 1; i <= sum / 2; i++) {
	        for (j = 1; j <= n; j++) {
	            part[i][j] = part[i][j - 1];
	            if (i >= arr[j - 1])
	                part[i][j] = part[i][j]
	                             || part[i - arr[j - 1]][j - 1];
	        }
	    }
	    return part[sum / 2][n];
	}

