public class ExploreSpace {

    public static void main(String[] args) {
        FastScanner fs=new FastScanner();
        PrintWriter out = new PrintWriter(System.out);
        int n = fs.nextInt();
        int m = fs.nextInt();
        int k = fs.nextInt();
        int[][] row = new int[n][m-1];
        int[][] col = new int[n-1][m];
        for(int i =0;i<n;i++){
            row[i] = fs.readArray(m-1);
        }
        for(int i =0;i<n-1;i++){
            col[i] = fs.readArray(m);
        }
        if(k%2!=0){
            for(int i =0;i<n;i++){
                for(int j =0;j<m;j++){
                    out.print("-1 ");
                }
                out.println();
            }
        }
        else{
            int[][] ans = new int[n][m];
            int[][] previous = new int[n][m];
            for(int turn =2;turn<=k;turn+=2){
                for(int i = 0;i<n;i++){
                    for(int j = 0;j<m;j++){
                        ans[i][j] = Integer.MAX_VALUE;
                        if(j>0){
                            int edge = row[i][j-1];
                            ans[i][j] = Math.min(ans[i][j],previous[i][j-1]+(2*edge));
                        }
                        if(j<m-1){
                            int edge = row[i][j];
                            ans[i][j] = Math.min(ans[i][j],previous[i][j+1]+(2*edge));
                        }
                        if(i>0){
                            int edge = col[i-1][j];
                            ans[i][j] = Math.min(ans[i][j],previous[i-1][j]+(2*edge));
                        }
                        if(i<n-1){
                            int edge = col[i][j];
                            ans[i][j] = Math.min(ans[i][j],previous[i+1][j]+(2*edge));
                        }   
                    }
                }
                for(int i =0;i<n;i++){
                    for(int j =0;j<m;j++){
                        previous[i][j] = ans[i][j];
                    }
                }
            }
            for(int i =0;i<n;i++){
                for(int j =0;j<m;j++){
                    out.print(ans[i][j]+" ");
                }
                out.println();
            }
        }
       out.close();
    }

