			for(int i = 0;i<N;i++) {
				for(int j = 0;j<M;j++) {
					grid[i][j] = new Node();
				}
			}
			for(int i = 0;i<N;i++) {
				for(int j = 0;j<M-1;j++) {
					grid[i][j].top = grid[i][j+1].bottom = reader.nextInt();
				}
			}
			for(int i = 0;i<N-1;i++) {
				for(int j = 0;j<M;j++) {
					grid[i][j].right = grid[i+1][j].left = reader.nextInt();
				}
			}

			int[][][] ansArr = new int[K/2 + 1][N][M];
			//base case: ansArr[0] is all 0s
			for(int k = 1; k<= K/2; k++) {
				for(int i = 0;i<N;i++) {
					for(int j = 0;j<M;j++) {
						int min = Integer.MAX_VALUE;
						if(i > 0) min = Math.min(min, ansArr[k-1][i-1][j] + 2*grid[i][j].left);
						if(i < N-1) min = Math.min(min, ansArr[k-1][i+1][j] + 2*grid[i][j].right);
						if(j > 0) min = Math.min(min, ansArr[k-1][i][j-1] + 2*grid[i][j].bottom);
						if(j < M-1) min = Math.min(min, ansArr[k-1][i][j+1] + 2*grid[i][j].top);
						ansArr[k][i][j] = min;
					}
				}
			}

			for(int i = 0;i<N;i++) {
				for(int j = 0;j<M;j++) {
					System.out.print(ansArr[K/2][i][j] + " ");
				}
				System.out.println();
			}
		}
