public class _718D {
    static BufferedReader br;
    static int [][][]dp;
    static int n, m;
    static int [][][]w;

    static class node{
        int x;
        int y;
        node(int xx, int yy){
            x = xx;
            y = yy;
        }
    }

    public static void main(String[] args) throws IOException {
        br = new BufferedReader(new InputStreamReader(System.in));
        int []a = readIntarray();
        n = a[0];
        m = a[1];
        int k = a[2];
        w = new int[n][m][4];
        dp = new int[n][m][k/2];
        for (int i = 0; i < n; i++) {
            int temp[] = readIntarray();
            for (int j = 0; j < m - 1; j++) {
                w[i][j][1] = temp[j];
                w[i][j+1][3] = temp[j];
            }
        }
        for (int i = 0; i < n - 1; i++) {
            int temp[] = readIntarray();
            for (int j = 0; j < m ; j++) {
                w[i][j][2] = temp[j];
                w[i+1][j][0] = temp[j];
            }
        }
        if(k%2 == 0) {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    dp[i][j][k / 2 - 1] = solve(i, j, k / 2);
                }
            }
        }
        for (int i = 0; i < n ; i++) {
            for (int j = 0; j < m ; j++) {
                System.out.print((k%2==0?dp[i][j][k/2-1]*2:-1) + " ");
            }
            System.out.println();
        }
    }

    static int solve(int x, int y, int k){
        if(k==0){
            return 0;
        }
        if(dp[x][y][k-1]>0){
            return dp[x][y][k-1];
        }

        int n_x = -1, n_y = -1;
        int min_w = Integer.MAX_VALUE;

        // Up
        if(x>0){
            n_x = x - 1;n_y = y;
            int t = solve(n_x, n_y, k - 1);
            if(t + w[x][y][0] < min_w){
                dp[x][y][k-1] = t + w[x][y][0];
                min_w = dp[x][y][k-1];
            }
        }

        // Right
        if(y<m-1){
            n_x = x; n_y = y + 1;
            int t = solve(n_x, n_y, k - 1);
            if(t + w[x][y][1] < min_w){
                dp[x][y][k-1] = t + w[x][y][1];
                min_w = dp[x][y][k-1];
            }
        }

        // Down
        if(x<n-1){
            n_x = x + 1;n_y = y;
            int t = solve(n_x, n_y, k - 1);
            if(t + w[x][y][2] < min_w){
                dp[x][y][k-1] = t + w[x][y][2];
                min_w = dp[x][y][k-1];
            }
        }

        // Left
        if(y>0){
            n_x = x; n_y = y - 1;
            int t = solve(n_x, n_y, k - 1);
            if(t + w[x][y][3] < min_w){
                dp[x][y][k-1] = t + w[x][y][3];
            }
        }

        return dp[x][y][k-1];
    }

    static int readInt() throws IOException {
        return Integer.parseInt(br.readLine());
    }

    static long readLong() throws IOException {
        return Long.parseLong(br.readLine());
    }

    static int[] readIntarray() throws IOException {
        String[] _a = br.readLine().split(" ");
        int[] _res = new int[_a.length];
        for (int i = 0; i < _a.length; i++) {
            _res[i] = Integer.parseInt(_a[i]);
        }
        return _res;
    }

    static long[] readLongarray() throws IOException {
        String[] _a = br.readLine().split(" ");
        long[] _res = new long[_a.length];
        for (int i = 0; i < _a.length; i++) {
            _res[i] = Long.parseLong(_a[i]);
        }
        return _res;
    }
}

