                    int dist = sc.nextInt();
                    graph[i][j][2] = dist;
                    graph[i+1][j][0] = dist;
                }
            }

            if(k % 2 == 0) {
                //find path from every node that has lowest cost
                for(int l = 1; l <= k/2; l++) {
                    for(int i = 0; i < n; i++) {
                        for(int j = 0; j < m; j++) {
                            int top = Integer.MAX_VALUE, right = Integer.MAX_VALUE, left = Integer.MAX_VALUE, bot = Integer.MAX_VALUE;
                            if(i > 0) {
                                top = graph[i][j][0] + dp[l-1][i-1][j];
                            }
                            if(j > 0) {
                                left = graph[i][j][3] + dp[l-1][i][j-1];
                            }
                            if(i < n-1) {
                                bot = graph[i][j][2] + dp[l-1][i+1][j];
                            }
                            if(j < m-1) {
                                right = graph[i][j][1] + dp[l-1][i][j+1];
                            }
                            dp[l][i][j] = Math.min(top, Math.min(right, Math.min(left, bot)));
                            //if(l == 1) System.out.println(top + " " + left +  " " + right + " " + bot);
                            //System.out.print(dp[l][i][j] + " ");
                        }
                        //System.out.println();
                    }
                    //System.out.println();
                }
            }

            for(int i = 0; i < n; i++) {
                for(int j = 0; j < m; j++) {
                    if(k%2 != 0) {
                        System.out.print("-1 ");
                    } else {
                        System.out.print(2*dp[k/2][i][j] + " ");
                    }
                }
                System.out.println();
            }
        }
    }
}

import java.util.Scanner;

public class explorer_space {

    static int mainarr[][][] ;

    static int dp(int hori_top[][], int ver_top[][] , int i , int j, int n , int m , int k) {
        if(k==0) {
            return 0 ;
        }
        int up = 10000000 ;
        int down = 10000000 ;
        int l_side = 10000000 ;
        int r_side = 10000000 ;
        if(i>= 1){
            int t = mainarr[i-1][j][k-1] == -1 ? dp(hori_top, ver_top, i-1, j, n, m, k-1) : mainarr[i-1][j][k-1] ;
            up = ver_top[i-1][j] + t ;
            mainarr[i-1][j][k-1] = t ;
        }
        if(i!=n-1){
            int t = mainarr[i+1][j][k-1] == -1 ? dp(hori_top, ver_top, i+1, j, n, m, k-1) : mainarr[i+1][j][k-1] ;
            down = ver_top[i][j] + t ;
            mainarr[i+1][j][k-1] = t ;
        }
        if(j>=1) {
            int t = mainarr[i][j-1][k-1] == -1 ? dp(hori_top, ver_top, i, j-1, n, m, k-1) : mainarr[i][j-1][k-1] ;
            l_side = hori_top[i][j-1] +t ;
            mainarr[i][j-1][k-1] = t ;
        }
        if(j!=m-1) {
            int t = mainarr[i][j+1][k-1] == -1 ? dp(hori_top, ver_top, i, j+1, n, m, k-1) : mainarr[i][j+1][k-1]  ;
            r_side = hori_top[i][j] + t ;
            mainarr[i][j+1][k-1] = t ; 
        }
        int upm = Math.min(up, down) ;
        int side = Math.min(l_side, r_side) ;
        return Math.min(upm, side) ;
    }
    public static void main(String[] args) {
        Scanner s = new Scanner (System.in) ;
        int n = s.nextInt() ;
        int m = s.nextInt() ;
        int k = s.nextInt() ;
        int hori_top[][] = new int [n][m-1] ;
        int ver_top[][] = new int [n-1][m] ;
        for(int i=0 ; i<n ; i++) {
            for(int j=0 ; j<m-1 ; j++) {
                hori_top[i][j] = s.nextInt() ;
            }
        }

        if(k%2 == 0) {
            mainarr = new int[n][m][k/2] ;
            for(int i=0 ; i<n ; i++) {
                for(int j=0 ; j<m ; j++) {
                    for(int l=0 ; l<k/2 ; l++) {
                        mainarr[i][j][l] = -1 ;
                    }
                }
            }
        }

        for(int i=0 ; i<n-1 ; i++) {
            for(int j=0 ; j<m ; j++) {
                ver_top[i][j] = s.nextInt() ;
            }
        }

        for(int i=0 ; i<n ; i++) {
            for(int j=0 ; j<m ; j++) {
                if(k%2 != 0){
                    System.out.print(-1 + " ");
                }
                else {
                    System.out.print(2*dp(hori_top , ver_top , i , j , n , m , k/2) + " ");
                }
            }
            System.out.println();
        }
    }
}

