import java.io.BufferedInputStream;
import java.io.BufferedOutputStream;
import java.io.PrintWriter;
import java.util.Locale;
import java.util.Scanner;

public class Main {

    public static void main(String[] args) throws Exception {
        try (BufferedInputStream in = new BufferedInputStream(System.in);
             PrintWriter out = new PrintWriter(new BufferedOutputStream(System.out))) {

            Scanner sc = new Scanner(in).useLocale(Locale.US);
//            int T = sc.nextInt();
//            for (int t = 0; t < T; t++) {
//        }
            int n = sc.nextInt();
            int m = sc.nextInt();
            int k = sc.nextInt();

            int[][] w1 = new int[n][m - 1];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m - 1; j++) {
                    w1[i][j] = sc.nextInt();
                }
            }
            int[][] w2 = new int[n - 1][m];
            for (int i = 0; i < n - 1; i++) {
                for (int j = 0; j < m; j++) {
                    w2[i][j] = sc.nextInt();
                }
            }

            if (k % 2 != 0) {
                for (int i = 0; i < n; i++) {
                    for (int j = 0; j < m; j++) {
                        out.print(-1 + " ");
                    }
                    out.println();
                }
                return;
            }

            int[][] neis = {{-1, 0}, {1, 0}, {0, 1}, {0, -1}};

            int[][] minDist = new int[n][m];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    minDist[i][j] = Integer.MAX_VALUE;
                    for (int[] nei : neis) {
                        int i1 = i + nei[0];
                        int j1 = j + nei[1];
                        if (0 <= i1 && i1 < n && 0 <= j1 && j1 < m) {
                            minDist[i][j] = Math.min(minDist[i][j], dist(i, j, i1, j1, w1, w2));
                        }
                    }
                }
            }

            int[][][] dp = new int[n][m][k + 1];
            for (int l = 2; l <= k; l += 2) {
                for (int i = 0; i < n; i++) {
                    for (int j = 0; j < m; j++) {
                        dp[i][j][l] = dp[i][j][l - 2] + 2 * minDist[i][j];
                        for (int[] nei : neis) {
                            int i1 = i + nei[0];
                            int j1 = j + nei[1];
                            if (0 <= i1 && i1 < n && 0 <= j1 && j1 < m) {
                                dp[i][j][l] = Math.min(dp[i][j][l],
                                                       2 * dist(i, j, i1, j1, w1, w2) + dp[i1][j1][l - 2]);
                            }
                        }
                    }
                }
            }

            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    out.print(dp[i][j][k] + " ");
                }
                out.println();
            }
        }
    }

    private static int dist(int i, int j, int i1, int j1, int[][] w1, int[][] w2) {
        if (i == i1) {
            return w1[i][Math.min(j, j1)];
        } else {
            return w2[Math.min(i, i1)][j];
        }
    }
}

