                }
                System.out.println();
            }
            return;
        }
        k /= 2;
        int[][][] dp = new int[n][m][2];
        int[][] h = new int[n][m];
        int[][] v = new int[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m - 1; j++) {
                h[i][j] = scanner.nextInt();
            }
        }
        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < m; j++) {
                v[i][j] = scanner.nextInt();
            }
        }
        for (int i = 0; i < k; i++) {
            for (int a = 0; a < n; a++) {
                for (int b = 0; b < m; b++) {
                    int t = Integer.MAX_VALUE;
                    if (a != n - 1) t = Math.min(t, dp[a + 1][b][1 - i % 2] + v[a][b] * 2);
                    if (a != 0) t = Math.min(t, dp[a - 1][b][1 - i % 2] + v[a - 1][b] * 2);
                    if (b != m - 1) t = Math.min(t, dp[a][b + 1][1 - i % 2] + h[a][b] * 2);
                    if (b != 0) t = Math.min(t, dp[a][b - 1][1 - i % 2] + h[a][b - 1] * 2);
                    dp[a][b][i % 2] = t;
                }
            }
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                System.out.print(dp[i][j][1 - k % 2] + " ");
            }
            System.out.println();
        }
    }
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.util.StringTokenizer;

public class prb {
    static int n, m, k;
    static int[][] w1, w2;

    public static void main(String[] args) {
        n = Reader.nextInt();
        m = Reader.nextInt();
        k = Reader.nextInt();
        if (k % 2 == 1) {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++)
                    System.out.print("-1 ");
                if (i != n - 1)
                    System.out.println();
            }
            return;
        }
        w1 = new int[n][m - 1];
        w2 = new int[n - 1][m];
        for (int i = 0; i < n; i++)
            for (int j = 0; j < m - 1; j++)
                w1[i][j] = Reader.nextInt();
        for (int i = 0; i < n - 1; i++)
            for (int j = 0; j < m; j++)
                w2[i][j] = Reader.nextInt();
        int[][][] b = new int[k / 2][n][m];
        for (int i = 0; i < n; i++)
            for (int j = 0; j < m; j++)
                for (int l = 0; l < k / 2; l++)
                    b[l][i][j] = Integer.MAX_VALUE;
        //b[0] init
        for (int i = 0; i < n; i++)
            for (int j = 0; j < m - 1; j++) {
                b[0][i][j] = Math.min(b[0][i][j], 2 * w1[i][j]);
                b[0][i][j + 1] = Math.min(b[0][i][j + 1], 2 * w1[i][j]);
            }
        for (int i = 0; i < n - 1; i++)
            for (int j = 0; j < m; j++) {
                b[0][i][j] = Math.min(b[0][i][j], 2 * w2[i][j]);
                b[0][i + 1][j] = Math.min(b[0][i + 1][j], 2 * w2[i][j]);
            }
        for (int l = 1; l < k/2; l++){
            for (int i = 0; i < n; i++)
                for (int j = 0; j < m - 1; j++) {
                    b[l][i][j] = Math.min(b[l][i][j], b[l-1][i][j+1] + 2 * w1[i][j]);
                    b[l][i][j + 1] = Math.min(b[l][i][j + 1], b[l-1][i][j] + 2 * w1[i][j]);
                }
            for (int i = 0; i < n - 1; i++)
                for (int j = 0; j < m; j++) {
                    b[l][i][j] = Math.min(b[l][i][j], b[l-1][i+1][j] + 2 * w2[i][j]);
                    b[l][i + 1][j] = Math.min(b[l][i + 1][j], b[l-1][i][j] + 2 * w2[i][j]);
                } 
        }

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++)
                System.out.print(b[k/2 - 1][i][j] + " ");
            if (i != n - 1)
                System.out.println();
        }
    }
}

class Reader {
    private static BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    public static StringTokenizer st;

    public static void setInput(InputStream inputStream) {
        br = new BufferedReader(new InputStreamReader(inputStream));
    }

    public static String next() {
        while (st == null || !st.hasMoreElements()) {
            try {
                st = new StringTokenizer(br.readLine());
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
        return st.nextToken();
    }


    public static int nextInt() {
        return Integer.parseInt(next());
    }
    public static char nextChar() {
        char str = 0;
        try {
            str = ((char) br.read());
        } catch (IOException e) {
            e.printStackTrace();
        }
        return str;
    }

    public static long nextLong() {
        return Long.parseLong(next());
    }

    public static double nextDouble() {
        return Double.parseDouble(next());
    }

    public static String nextLine() {
        String str = "";
        try {
            str = br.readLine();
        } catch (IOException e) {
            e.printStackTrace();
        }
        return str;
    }
}
